-- Migration 013: Extend questions from 35 to 55 per topic (order_index 36-55)
-- 10 topics × 3 tracks × 20 questions = 600 new questions

-- ============================================================
-- TOPIC 1: Logic & Boolean Algebra
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Logic & Boolean Algebra' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'If you need BOTH a key AND a password to open a treasure chest, what kind of rule is that?', '["AND rule","OR rule","NOT rule","XOR rule"]'::jsonb, 'AND rule', 'When two things must both be true at the same time, we call it an AND rule.', true),
  (gen_random_uuid(), tid, 'story', 37, 'A light turns on if you flip switch A OR switch B. If only switch B is flipped, does the light turn on?', '["Yes","No","Only if A is also flipped","It depends on the day"]'::jsonb, 'Yes', 'With an OR rule, the light turns on when at least one switch is flipped.', true),
  (gen_random_uuid(), tid, 'story', 38, 'What does the NOT rule do to the word TRUE?', '["Turns it into FALSE","Turns it into MAYBE","Keeps it TRUE","Doubles it"]'::jsonb, 'Turns it into FALSE', 'The NOT rule flips the value: NOT TRUE becomes FALSE, and NOT FALSE becomes TRUE.', true),
  (gen_random_uuid(), tid, 'story', 39, 'You can enter the clubhouse if you are a member AND you know the secret knock. You are a member but forgot the knock. Can you enter?', '["No","Yes","Only on weekends","Ask a grown-up"]'::jsonb, 'No', 'Both conditions must be true for AND, so forgetting the knock means you cannot enter.', true),
  (gen_random_uuid(), tid, 'story', 40, 'In a true/false world, how many different values can one bit hold?', '["2","1","4","8"]'::jsonb, '2', 'A single bit is either 0 (false) or 1 (true), giving exactly two possible values.', true),
  (gen_random_uuid(), tid, 'story', 41, 'A robot opens a door when the button is pressed OR the timer goes off. If neither happens, does the door open?', '["No","Yes","Only at night","Always"]'::jsonb, 'No', 'OR requires at least one condition to be true; if both are false the result is false.', true),
  (gen_random_uuid(), tid, 'story', 42, 'What is the result of TRUE AND FALSE?', '["FALSE","TRUE","MAYBE","BOTH"]'::jsonb, 'FALSE', 'AND only gives TRUE when both sides are TRUE; one FALSE makes the whole thing FALSE.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What is the result of FALSE OR TRUE?', '["TRUE","FALSE","UNKNOWN","NEITHER"]'::jsonb, 'TRUE', 'OR gives TRUE whenever at least one side is TRUE.', true),
  (gen_random_uuid(), tid, 'story', 44, 'If it is NOT raining, should you bring an umbrella according to the NOT rule?', '["No","Yes","Always bring one","Only in winter"]'::jsonb, 'No', 'NOT raining means it is sunny, so the umbrella is not needed based on the rule.', true),
  (gen_random_uuid(), tid, 'story', 45, 'A cookie jar opens when you say the magic word AND clap your hands. You say the word but do not clap. What happens?', '["The jar stays closed","The jar opens","It explodes","It spins around"]'::jsonb, 'The jar stays closed', 'AND requires both actions; missing one keeps the result false.', true),
  (gen_random_uuid(), tid, 'story', 46, 'Which gate takes one input and gives the opposite output?', '["NOT gate","AND gate","OR gate","ADD gate"]'::jsonb, 'NOT gate', 'The NOT gate (inverter) has one input and flips it to the opposite value.', true),
  (gen_random_uuid(), tid, 'story', 47, 'TRUE OR TRUE equals what?', '["TRUE","FALSE","SUPER TRUE","ZERO"]'::jsonb, 'TRUE', 'OR is true whenever at least one input is true, so TRUE OR TRUE is TRUE.', true),
  (gen_random_uuid(), tid, 'story', 48, 'FALSE AND FALSE equals what?', '["FALSE","TRUE","HALF","ONE"]'::jsonb, 'FALSE', 'AND is only true when both inputs are true; both false gives false.', true),
  (gen_random_uuid(), tid, 'story', 49, 'You score a prize if you spin the wheel OR answer the question. You answer the question correctly. Do you win?', '["Yes","No","Only if you also spin","Ask the host"]'::jsonb, 'Yes', 'OR means success with at least one condition met, and you answered correctly.', true),
  (gen_random_uuid(), tid, 'story', 50, 'Logic uses only two answers. What are they?', '["True and False","Yes and Maybe","Big and Small","Fast and Slow"]'::jsonb, 'True and False', 'Boolean logic works with exactly two values: true and false (or 1 and 0).', true),
  (gen_random_uuid(), tid, 'story', 51, 'If a rule says NOT (TRUE AND FALSE), what is the answer?', '["TRUE","FALSE","MAYBE","ERROR"]'::jsonb, 'TRUE', 'TRUE AND FALSE is FALSE, and NOT FALSE is TRUE.', true),
  (gen_random_uuid(), tid, 'story', 52, 'A toy robot beeps when button A is pressed AND the battery is full. The battery is dead. Will it beep when you press A?', '["No","Yes","Sometimes","Always"]'::jsonb, 'No', 'AND requires both conditions; a dead battery makes one condition false, so no beep.', true),
  (gen_random_uuid(), tid, 'story', 53, 'Which word means the same as the AND rule in everyday language?', '["Both","Either","Neither","Not"]'::jsonb, 'Both', 'AND means both things must be true, just like saying "I want this AND that."', true),
  (gen_random_uuid(), tid, 'story', 54, 'What do we call a diagram that shows all possible true/false inputs and outputs for a logic rule?', '["Truth table","Score card","Map key","Recipe"]'::jsonb, 'Truth table', 'A truth table lists every combination of inputs and the resulting output for a logic operation.', true),
  (gen_random_uuid(), tid, 'story', 55, 'If NOT FALSE equals TRUE, what does NOT TRUE equal?', '["FALSE","TRUE","ZERO","ONE"]'::jsonb, 'FALSE', 'NOT always flips the value, so NOT TRUE becomes FALSE.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'Which Boolean expression correctly represents "A is true but B is not"?', '["A AND NOT B","A OR NOT B","NOT A AND B","NOT (A OR B)"]'::jsonb, 'A AND NOT B', 'We need A to be true and B to be false, written as A AND NOT B.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'In a truth table for a two-input AND gate, how many rows show output = 1?', '["1","2","3","4"]'::jsonb, '1', 'AND outputs 1 only when both inputs are 1, giving exactly one true row out of four.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What is the dual of the AND operation according to De Morgan''s theorem?', '["OR","NOT","XOR","NAND"]'::jsonb, 'OR', 'De Morgan''s theorem shows AND and OR are duals: NOT(A AND B) = NOT A OR NOT B.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'Which gate outputs TRUE only when its inputs are different?', '["XOR","XNOR","AND","NOR"]'::jsonb, 'XOR', 'XOR (exclusive OR) is true when exactly one input is true, i.e., inputs differ.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'Simplify: A AND (A OR B)', '["A","B","A OR B","A AND B"]'::jsonb, 'A', 'By the absorption law, A AND (A OR B) simplifies to A.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'How many bits are needed to represent 8 different values?', '["3","4","8","2"]'::jsonb, '3', '2^3 = 8, so three bits can represent exactly 8 unique values (0–7).', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What is the output of NAND(1, 1)?', '["0","1","2","Undefined"]'::jsonb, '0', 'NAND is NOT AND; AND(1,1)=1, so NAND(1,1)=0.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'Which law states that A OR (B AND C) = (A OR B) AND (A OR C)?', '["Distributive law","Commutative law","Associative law","Absorption law"]'::jsonb, 'Distributive law', 'The distributive law allows distributing OR over AND (and vice versa) in Boolean algebra.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'In a game, a player wins if they have score > 100 AND lives > 0. Which row wins? [score=105, lives=1]', '["Row wins","Row loses","Needs more info","Tie"]'::jsonb, 'Row wins', 'Both conditions are true (105 > 100 and 1 > 0), so the AND evaluates to true.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What does the NOR gate output when both inputs are 0?', '["1","0","Undefined","Depends on voltage"]'::jsonb, '1', 'NOR is NOT OR; OR(0,0)=0, so NOR(0,0)=1.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'Which Boolean identity is known as the identity law for OR?', '["A OR 0 = A","A OR 1 = 1","A OR A = A","A OR NOT A = 1"]'::jsonb, 'A OR 0 = A', 'The identity law states that ORing with 0 leaves the value unchanged.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'How many rows does a truth table for 3 variables have?', '["8","6","4","16"]'::jsonb, '8', '2^3 = 8 combinations exist for three binary variables.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'Simplify: NOT(NOT A)', '["A","NOT A","TRUE","FALSE"]'::jsonb, 'A', 'Double negation cancels out, so NOT(NOT A) = A (involution law).', true),
  (gen_random_uuid(), tid, 'levels', 49, 'A combination lock opens if code = 1234 OR fingerprint matches. Only the fingerprint matches. Does it open?', '["Yes","No","Only with admin key","It resets"]'::jsonb, 'Yes', 'OR requires only one condition to be true; fingerprint match is sufficient.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'Which gate is called a "universal gate" because it can build any other gate?', '["NAND","XOR","NOR gate only","AND"]'::jsonb, 'NAND', 'NAND is universal: every other logic gate can be constructed using only NAND gates.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is the result of A XOR A?', '["0","1","A","NOT A"]'::jsonb, '0', 'XOR of identical inputs is always 0 because the inputs are never different.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'In Boolean algebra, what is A AND 0?', '["0","1","A","NOT A"]'::jsonb, '0', 'ANDing any value with 0 forces the result to 0 (null element law).', true),
  (gen_random_uuid(), tid, 'levels', 53, 'Apply De Morgan: NOT(A OR B) = ?', '["NOT A AND NOT B","NOT A OR NOT B","A AND B","NOT(A AND B)"]'::jsonb, 'NOT A AND NOT B', 'De Morgan''s theorem: NOT(A OR B) = NOT A AND NOT B.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'Which expression equals 1 for all values of A?', '["A OR NOT A","A AND NOT A","A XOR A","A AND A"]'::jsonb, 'A OR NOT A', 'A OR NOT A is always 1 (tautology / complement law).', true),
  (gen_random_uuid(), tid, 'levels', 55, 'A 4-input AND gate outputs 1. How many inputs must be 1?', '["All 4","At least 1","Exactly 2","3 or more"]'::jsonb, 'All 4', 'AND requires every single input to be 1 to produce a 1 output.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'In CMOS logic design, why is NAND preferred over AND as a primitive gate?', '["NAND requires fewer transistors than AND","AND is faster","NAND cannot be inverted","AND uses less power"]'::jsonb, 'NAND requires fewer transistors than AND', 'A CMOS AND gate requires a NAND followed by an inverter, so NAND alone is simpler and more area-efficient.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'Which canonical form expresses a Boolean function as a sum of minterms?', '["Sum of Products (SOP)","Product of Sums (POS)","Karnaugh Map","Boolean Lattice"]'::jsonb, 'Sum of Products (SOP)', 'SOP (sum of minterms) ORs together AND terms where the function outputs 1.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'A Karnaugh map for 4 variables has how many cells?', '["16","8","32","4"]'::jsonb, '16', '4 variables yield 2^4 = 16 possible minterms, one per K-map cell.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'Which Boolean law allows rewriting (A AND B) AND C as A AND (B AND C)?', '["Associative law","Commutative law","Distributive law","Idempotent law"]'::jsonb, 'Associative law', 'The associative law states grouping does not affect the result: (A·B)·C = A·(B·C).', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What term describes a Boolean expression that is true for every possible input combination?', '["Tautology","Contradiction","Contingency","Minterm"]'::jsonb, 'Tautology', 'A tautology evaluates to true regardless of the input values, e.g., A OR NOT A.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'In Boolean algebra over GF(2), what operation corresponds to addition?', '["XOR","OR","AND","XNOR"]'::jsonb, 'XOR', 'GF(2) arithmetic uses XOR as addition (modulo 2) and AND as multiplication.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is the minimum number of NAND gates required to implement a 2-input XOR gate?', '["4","2","3","5"]'::jsonb, '4', 'A 2-input XOR can be built with 4 NAND gates using the standard implementation.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'Which minimization technique groups minterms in powers of 2 on a grid to find prime implicants?', '["Karnaugh map","Quine-McCluskey","Boolean expansion","Shannon decomposition"]'::jsonb, 'Karnaugh map', 'K-maps visually group adjacent minterms in powers of 2 to identify and eliminate redundant literals.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'In a hazard-free combinational circuit, what causes a static-1 hazard?', '["A momentary glitch to 0 when output should stay 1","A clock skew issue","A feedback loop","An unconnected input"]'::jsonb, 'A momentary glitch to 0 when output should stay 1', 'A static-1 hazard occurs when propagation delay differences cause a brief 0 on an output that should remain 1.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'Which Boolean identity is used to implement multiplexers from basic gates? A = (A AND S) OR (A AND NOT S)', '["Consensus theorem","Shannon expansion","Absorption law","Complement law"]'::jsonb, 'Shannon expansion', 'Shannon''s expansion theorem decomposes a function based on a variable, directly modeling MUX behavior.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'How does the Quine-McCluskey algorithm differ from Karnaugh maps?', '["It is algorithmic and scales to many variables; K-maps are limited to ~6 variables","It only works for 2 variables","It cannot find prime implicants","It requires analog hardware"]'::jsonb, 'It is algorithmic and scales to many variables; K-maps are limited to ~6 variables', 'Quine-McCluskey is a tabular algorithm suited for computer implementation with many variables, unlike visual K-maps.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'In a programmable logic array (PLA), which two planes implement sum-of-products logic?', '["AND plane and OR plane","NOR plane and NAND plane","XOR plane and XNOR plane","Flip-flop plane and latch plane"]'::jsonb, 'AND plane and OR plane', 'A PLA uses an AND plane to form product terms and an OR plane to sum them, realising SOP expressions.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What property makes Boolean algebra a Boolean lattice (complemented distributive lattice)?', '["Every element has a complement and both distributive laws hold","Elements can take any real value","Operations are not associative","It requires three-valued logic"]'::jsonb, 'Every element has a complement and both distributive laws hold', 'A Boolean lattice requires complementation, distributivity of meet over join (and vice versa), and bounded elements.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'Which logic family has the lowest static power consumption at rest?', '["CMOS","TTL","ECL","RTL"]'::jsonb, 'CMOS', 'CMOS draws near-zero static current because complementary PMOS/NMOS pairs are never both on simultaneously at rest.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'In formal verification, what technique checks whether two Boolean circuits are equivalent?', '["Binary Decision Diagrams (BDDs)","Simulation only","Manual inspection","Truth tables for all 2^n inputs"]'::jsonb, 'Binary Decision Diagrams (BDDs)', 'BDDs provide a canonical representation of Boolean functions, enabling efficient equivalence checking without exhaustive enumeration.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What does the consensus theorem state for Boolean algebra?', '["XY OR NOT X Z OR YZ = XY OR NOT X Z","A OR A = A","A AND 1 = A","NOT(NOT A) = A"]'::jsonb, 'XY OR NOT X Z OR YZ = XY OR NOT X Z', 'The consensus theorem allows elimination of the redundant term YZ when XY and NOT X Z are both present.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'A security system requires: (door_sensor OR window_sensor) AND alarm_enabled AND NOT override. This is an example of which design pattern?', '["Guard clause logic","Race condition","Deadlock","Buffer overflow"]'::jsonb, 'Guard clause logic', 'Combining multiple boolean conditions to control system behavior is a classic guard clause or predicate logic pattern.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'Which theorem states that any Boolean function can be expressed using only AND, OR, and NOT?', '["Functional completeness theorem","Shannon theorem","De Morgan theorem","Boole''s theorem"]'::jsonb, 'Functional completeness theorem', 'The set {AND, OR, NOT} is functionally complete, meaning any Boolean function can be built from these three operations.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'In a 32-bit ALU, how many bits wide is the carry chain that determines addition latency?', '["32","1","16","64"]'::jsonb, '32', 'In a ripple-carry adder, carry must propagate through all 32 stages, making the chain 32 bits wide.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is the primary advantage of carry-lookahead adders over ripple-carry adders?', '["Faster addition by computing carries in parallel","Using fewer gates","Simpler circuit design","Lower power consumption always"]'::jsonb, 'Faster addition by computing carries in parallel', 'Carry-lookahead adders precompute carry signals using generate and propagate logic, removing the serial dependency.', true);
END;
$$;

-- ============================================================
-- TOPIC 2: Algorithmic Thinking
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Algorithmic Thinking' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'An algorithm is like a recipe. What must a recipe have to work every time?', '["Clear steps in order","A fancy name","Expensive ingredients","A picture"]'::jsonb, 'Clear steps in order', 'Just like a recipe, an algorithm needs clear, ordered steps so it always gives the same result.', true),
  (gen_random_uuid(), tid, 'story', 37, 'You want to find your favorite toy in a messy room. Checking every corner one by one is called what?', '["Searching","Jumping","Guessing","Skipping"]'::jsonb, 'Searching', 'Checking items one by one until you find what you need is a basic search algorithm.', true),
  (gen_random_uuid(), tid, 'story', 38, 'If you sort your crayons from shortest to longest, what are you doing?', '["Ordering them","Coloring them","Breaking them","Hiding them"]'::jsonb, 'Ordering them', 'Arranging items from smallest to largest (or any consistent rule) is called sorting.', true),
  (gen_random_uuid(), tid, 'story', 39, 'A loop in an algorithm means you do something again and again until when?', '["Until a condition is met","Forever","Only once","Twice"]'::jsonb, 'Until a condition is met', 'Loops repeat steps until a specific condition (like finishing a list) becomes true.', true),
  (gen_random_uuid(), tid, 'story', 40, 'What is the first step when writing an algorithm to solve a problem?', '["Understand the problem","Write the code","Test it","Delete it"]'::jsonb, 'Understand the problem', 'You must clearly understand what the problem is before you can design steps to solve it.', true),
  (gen_random_uuid(), tid, 'story', 41, 'If you make a mistake in one step of a recipe, what might happen to the whole meal?', '["It could turn out wrong","It gets better","Nothing changes","It cooks faster"]'::jsonb, 'It could turn out wrong', 'One wrong step can ruin the result — algorithms must be correct at every step.', true),
  (gen_random_uuid(), tid, 'story', 42, 'You check if it is raining before deciding to bring an umbrella. This is called a what?', '["Decision","Loop","Sort","Delete"]'::jsonb, 'Decision', 'Checking a condition and choosing different actions is a decision (if-then) step in an algorithm.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What do we call breaking a big problem into smaller, easier parts?', '["Decomposition","Decoration","Destruction","Description"]'::jsonb, 'Decomposition', 'Decomposition means splitting a complex problem into smaller pieces that are easier to solve.', true),
  (gen_random_uuid(), tid, 'story', 44, 'Which word describes finding and fixing mistakes in an algorithm?', '["Debugging","Drawing","Dancing","Deleting"]'::jsonb, 'Debugging', 'Debugging is the process of finding and correcting errors (bugs) in an algorithm or program.', true),
  (gen_random_uuid(), tid, 'story', 45, 'If you fold laundry the same way every time, your folding method is like what?', '["An algorithm","A riddle","A game","A story"]'::jsonb, 'An algorithm', 'Any repeatable set of steps that always produces the same result is like an algorithm.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What does it mean when an algorithm is "efficient"?', '["It solves the problem quickly without wasting steps","It uses many colors","It is very long","It needs lots of help"]'::jsonb, 'It solves the problem quickly without wasting steps', 'An efficient algorithm reaches the correct answer using as few steps and as little time as possible.', true),
  (gen_random_uuid(), tid, 'story', 47, 'You want to count all the apples in a basket. You count each one. When do you stop?', '["When you have counted every apple","When you are tired","After ten","Never"]'::jsonb, 'When you have counted every apple', 'The stopping condition for counting is when all items have been counted — this is the algorithm''s end condition.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What is a flowchart used for?', '["Showing the steps of an algorithm with shapes and arrows","Drawing flowers","Making music","Building blocks"]'::jsonb, 'Showing the steps of an algorithm with shapes and arrows', 'A flowchart is a diagram that maps out an algorithm''s steps using shapes and directional arrows.', true),
  (gen_random_uuid(), tid, 'story', 49, 'In an algorithm, what does the word "input" mean?', '["The information you give to the algorithm","The answer it produces","A kind of loop","A mistake"]'::jsonb, 'The information you give to the algorithm', 'Input is the data or information you provide to an algorithm so it can do its work.', true),
  (gen_random_uuid(), tid, 'story', 50, 'What is the "output" of an algorithm?', '["The result or answer it produces","The first step","The loop","The mistake"]'::jsonb, 'The result or answer it produces', 'Output is what the algorithm produces after processing the input.', true),
  (gen_random_uuid(), tid, 'story', 51, 'You ask a friend to follow your directions to your house. What must your directions be to work?', '["Clear and in the right order","Funny","Very long","Secret"]'::jsonb, 'Clear and in the right order', 'Directions, like algorithms, must be unambiguous and sequenced correctly to lead to the right destination.', true),
  (gen_random_uuid(), tid, 'story', 52, 'Which of these is NOT a step in creating an algorithm?', '["Painting a picture","Identifying the problem","Writing the steps","Testing the solution"]'::jsonb, 'Painting a picture', 'Creating an algorithm involves identifying the problem, designing steps, and testing — painting is not part of the process.', true),
  (gen_random_uuid(), tid, 'story', 53, 'What does it mean when we say an algorithm "terminates"?', '["It stops after finishing its work","It starts over","It loops forever","It breaks"]'::jsonb, 'It stops after finishing its work', 'An algorithm that terminates reaches a definite end point rather than running forever.', true),
  (gen_random_uuid(), tid, 'story', 54, 'If two people use the same algorithm on the same problem, what should they get?', '["The same answer","Different answers","No answer","A random answer"]'::jsonb, 'The same answer', 'Algorithms are deterministic — the same input always produces the same output regardless of who runs it.', true),
  (gen_random_uuid(), tid, 'story', 55, 'What is a "sequence" in an algorithm?', '["Steps done one after another in order","All steps at the same time","A random order","A single step"]'::jsonb, 'Steps done one after another in order', 'Sequence is a fundamental concept — steps are executed in a defined order from first to last.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What is the time complexity of searching for an item in an unsorted list of n items by checking each one?', '["O(n)","O(log n)","O(n²)","O(1)"]'::jsonb, 'O(n)', 'Linear search checks each element once in the worst case, giving O(n) time complexity.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'Binary search requires the list to be what before it works?', '["Sorted","Unsorted","Even-length","Unique"]'::jsonb, 'Sorted', 'Binary search works by repeatedly halving the search space, which only works on a sorted list.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'Which sorting algorithm repeatedly swaps adjacent elements that are in the wrong order?', '["Bubble sort","Merge sort","Quick sort","Heap sort"]'::jsonb, 'Bubble sort', 'Bubble sort compares and swaps neighboring elements, "bubbling" the largest values to the end.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What is a recursive algorithm?', '["One that calls itself to solve smaller versions of the same problem","One that never ends","One that uses loops only","One that sorts data"]'::jsonb, 'One that calls itself to solve smaller versions of the same problem', 'Recursion is when a function solves a problem by breaking it into smaller sub-problems and calling itself.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What must every recursive algorithm have to prevent infinite loops?', '["A base case","A loop","An array","A sort"]'::jsonb, 'A base case', 'The base case is the condition that stops recursion, preventing it from running forever.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'An algorithm that always finds the optimal solution is called what?', '["Exact algorithm","Greedy algorithm","Heuristic","Approximation"]'::jsonb, 'Exact algorithm', 'An exact algorithm guarantees finding the optimal solution, unlike heuristics that may find good but not perfect solutions.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What does O(1) time complexity mean?', '["The algorithm takes constant time regardless of input size","It takes one second","It sorts in one pass","It uses one variable"]'::jsonb, 'The algorithm takes constant time regardless of input size', 'O(1) means the operation completes in the same amount of time no matter how large the input is.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'Which algorithm strategy divides the problem in half each time?', '["Divide and conquer","Brute force","Greedy","Dynamic programming"]'::jsonb, 'Divide and conquer', 'Divide and conquer splits the problem into halves (or parts), solves each, then combines the results.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is a pseudocode?', '["Informal description of an algorithm using plain language and code-like structure","Actual programming code","A type of loop","A debugging tool"]'::jsonb, 'Informal description of an algorithm using plain language and code-like structure', 'Pseudocode bridges human language and programming, making it easy to plan logic before writing real code.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'How many comparisons does binary search need at most for a list of 128 items?', '["7","128","64","15"]'::jsonb, '7', 'Binary search has O(log n) complexity; log₂(128) = 7, so at most 7 comparisons are needed.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What does it mean for an algorithm to be "correct"?', '["It produces the right output for all valid inputs","It runs fast","It has no loops","It uses recursion"]'::jsonb, 'It produces the right output for all valid inputs', 'Correctness means the algorithm satisfies its specification for every valid input case.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'Which data structure does a stack use for adding and removing items?', '["Last In First Out (LIFO)","First In First Out (FIFO)","Random order","Sorted order"]'::jsonb, 'Last In First Out (LIFO)', 'A stack adds and removes items from the same end (top), following the LIFO principle.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is the worst-case time complexity of bubble sort?', '["O(n²)","O(n)","O(log n)","O(n log n)"]'::jsonb, 'O(n²)', 'Bubble sort has a nested loop structure, resulting in O(n²) comparisons in the worst case.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What does it mean to "trace" an algorithm?', '["Manually follow each step to see what happens with specific inputs","Delete it","Speed it up","Rename it"]'::jsonb, 'Manually follow each step to see what happens with specific inputs', 'Tracing an algorithm means walking through each step by hand to verify behavior and find errors.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'Which approach solves a problem by trying every possible solution?', '["Brute force","Greedy","Binary search","Heuristic"]'::jsonb, 'Brute force', 'Brute force exhaustively tries all possibilities, guaranteeing a solution but often being inefficient.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is an "edge case" in algorithm testing?', '["An unusual or extreme input that might cause errors","The last item in a list","A sorting error","A type of loop"]'::jsonb, 'An unusual or extreme input that might cause errors', 'Edge cases are boundary or unusual inputs (like empty lists or maximum values) that often reveal bugs.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'Merge sort has which time complexity in the worst case?', '["O(n log n)","O(n²)","O(n)","O(log n)"]'::jsonb, 'O(n log n)', 'Merge sort divides and merges in O(log n) levels with O(n) work each level, giving O(n log n) overall.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What is the purpose of a counter variable in a loop?', '["To track how many times the loop has run","To store the answer","To name the loop","To stop the program"]'::jsonb, 'To track how many many times the loop has run', 'A counter variable increments with each iteration, letting the algorithm know when to stop the loop.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'If an algorithm works correctly on small inputs but crashes on large ones, what is likely the problem?', '["It is not scalable — complexity is too high","The input is wrong","It has no loops","It is recursive"]'::jsonb, 'It is not scalable — complexity is too high', 'Poor scalability means the algorithm''s time or memory usage grows too fast for large inputs.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What is the Fibonacci sequence algorithm an example of?', '["Recursion","Binary search","Bubble sort","Greedy"]'::jsonb, 'Recursion', 'Fibonacci is classically defined recursively: F(n) = F(n-1) + F(n-2), with base cases F(0)=0 and F(1)=1.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the average-case time complexity of quicksort?', '["O(n log n)","O(n²)","O(n)","O(log n)"]'::jsonb, 'O(n log n)', 'Quicksort achieves O(n log n) on average with a good pivot, though worst-case with bad pivots is O(n²).', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'Which algorithm paradigm stores solutions to subproblems to avoid redundant computation?', '["Dynamic programming","Divide and conquer","Greedy","Backtracking"]'::jsonb, 'Dynamic programming', 'Dynamic programming uses memoization or tabulation to store and reuse subproblem solutions, reducing exponential recursion.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What distinguishes a greedy algorithm from dynamic programming?', '["Greedy makes locally optimal choices without reconsidering; DP considers all subproblems","Greedy is always slower","DP cannot solve optimization problems","Greedy uses more memory"]'::jsonb, 'Greedy makes locally optimal choices without reconsidering; DP considers all subproblems', 'Greedy algorithms commit to local optima at each step, while DP explores all possibilities systematically.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'What is the space complexity of an iterative vs. recursive implementation of a simple loop?', '["O(1) iterative vs. O(n) recursive due to call stack","Both O(n)","Both O(1)","O(log n) iterative vs. O(1) recursive"]'::jsonb, 'O(1) iterative vs. O(n) recursive due to call stack', 'Each recursive call adds a stack frame; n recursive calls use O(n) stack space, while iteration uses O(1).', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'Which algorithm finds the shortest path in a weighted graph with non-negative edges?', '["Dijkstra''s algorithm","Bellman-Ford","DFS","BFS"]'::jsonb, 'Dijkstra''s algorithm', 'Dijkstra''s algorithm uses a priority queue to greedily expand the shortest known path, working correctly with non-negative weights.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What is amortized time complexity?', '["The average cost per operation over a sequence of operations","The worst single operation cost","Memory usage","The best-case time"]'::jsonb, 'The average cost per operation over a sequence of operations', 'Amortized analysis averages the cost over many operations, useful when occasional expensive operations are offset by cheap ones.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'Which sorting algorithm is stable and uses O(n) extra space?', '["Merge sort","Quicksort","Heap sort","Selection sort"]'::jsonb, 'Merge sort', 'Merge sort is stable (equal elements maintain order) and requires O(n) auxiliary space for merging.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What property must a problem have for dynamic programming to be applicable?', '["Optimal substructure and overlapping subproblems","NP-hardness","Polynomial inputs only","Unique solutions"]'::jsonb, 'Optimal substructure and overlapping subproblems', 'DP requires that optimal solutions to subproblems compose into an optimal overall solution, and that subproblems repeat.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'In the context of NP-completeness, what does a polynomial-time reduction prove?', '["That one problem is at least as hard as another","That a problem is solvable","That P equals NP","That the algorithm is greedy"]'::jsonb, 'That one problem is at least as hard as another', 'A poly-time reduction from problem A to B shows B is at least as hard as A, used to prove NP-hardness.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is the key operation that makes heapsort efficient?', '["Maintaining the heap property via sift-down in O(log n)","Linear scans","Random pivoting","Recursive merging"]'::jsonb, 'Maintaining the heap property via sift-down in O(log n)', 'Heapsort builds a max-heap then repeatedly extracts the maximum using sift-down, each in O(log n) time.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'Which algorithm technique explores all branches of a decision tree and backtracks when a branch fails?', '["Backtracking","Dynamic programming","Greedy","Divide and conquer"]'::jsonb, 'Backtracking', 'Backtracking explores partial solutions and abandons (backtracks from) branches that cannot lead to a valid solution.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is the difference between BFS and DFS traversal of a graph?', '["BFS explores level by level using a queue; DFS explores depth-first using a stack","BFS is always faster","DFS cannot find shortest paths in any graph","They are identical"]'::jsonb, 'BFS explores level by level using a queue; DFS explores depth-first using a stack', 'BFS uses a queue for breadth-first traversal (optimal for unweighted shortest paths); DFS uses a stack for depth exploration.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What does it mean for an algorithm to be in-place?', '["It uses O(1) extra memory beyond the input","It runs on a single processor","It never uses recursion","It sorts only integers"]'::jsonb, 'It uses O(1) extra memory beyond the input', 'An in-place algorithm modifies the input data structure directly without requiring significant additional memory.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'Which algorithm solves the all-pairs shortest path problem in O(V³) time?', '["Floyd-Warshall","Dijkstra''s","Bellman-Ford","Prim''s"]'::jsonb, 'Floyd-Warshall', 'Floyd-Warshall uses dynamic programming with three nested loops over vertices, giving O(V³) time complexity.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is tail recursion and why is it important?', '["A recursive call as the last operation, enabling compiler optimization to avoid stack growth","A loop at the end of a function","A base case","A type of merge sort"]'::jsonb, 'A recursive call as the last operation, enabling compiler optimization to avoid stack growth', 'Tail calls can be optimized by compilers to reuse the current stack frame, converting recursion to iteration.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'In the Master Theorem, what case applies when f(n) = O(n^(log_b(a) - ε))?', '["Case 1: T(n) = O(n^log_b(a))","Case 2","Case 3","The theorem does not apply"]'::jsonb, 'Case 1: T(n) = O(n^log_b(a))', 'Master Theorem Case 1 applies when the recursive work dominates; the solution is O(n^log_b(a)).', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What makes the A* search algorithm more efficient than Dijkstra''s in practice?', '["A* uses a heuristic to guide search toward the goal, reducing explored nodes","A* is always O(1)","A* does not use a priority queue","A* only works on trees"]'::jsonb, 'A* uses a heuristic to guide search toward the goal, reducing explored nodes', 'A* combines path cost with an admissible heuristic estimate, focusing exploration toward the target.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What is the significance of the P vs NP problem?', '["It asks whether every problem whose solution can be verified quickly can also be solved quickly","It determines the best sorting algorithm","It defines recursion","It relates to memory limits"]'::jsonb, 'It asks whether every problem whose solution can be verified quickly can also be solved quickly', 'P vs NP is an unsolved question asking if polynomial-time verification implies polynomial-time solvability.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'Which data structure supports O(log n) insertion, deletion, and search, and is used in many standard library implementations?', '["Balanced BST (e.g., Red-Black tree)","Unsorted array","Hash table","Linked list"]'::jsonb, 'Balanced BST (e.g., Red-Black tree)', 'Red-Black trees and AVL trees maintain balance guaranteeing O(log n) for all basic operations.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is the computational complexity of the naive matrix multiplication algorithm for n×n matrices?', '["O(n³)","O(n²)","O(n log n)","O(n² log n)"]'::jsonb, 'O(n³)', 'The naive algorithm uses three nested loops over n, resulting in O(n³) multiplications and additions.', true);
END;
$$;

-- ============================================================
-- TOPIC 3: Data Structures
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Data Structures' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'A stack of pancakes where you always add and remove from the top is like which data structure?', '["Stack","Queue","List","Tree"]'::jsonb, 'Stack', 'A stack works just like pancakes — you add to and remove from the top (last in, first out).', true),
  (gen_random_uuid(), tid, 'story', 37, 'A line of people waiting for a movie ticket — the first person in line is served first. This is like a what?', '["Queue","Stack","Tree","Map"]'::jsonb, 'Queue', 'A queue serves the first item added first, just like a line of people waiting.', true),
  (gen_random_uuid(), tid, 'story', 38, 'You have a list of your favorite animals: cat, dog, bird. What kind of data structure stores items in order?', '["Array","Tree","Graph","Hash"]'::jsonb, 'Array', 'An array stores items in a numbered order, like slots 0, 1, 2 for cat, dog, bird.', true),
  (gen_random_uuid(), tid, 'story', 39, 'A family tree shows parents above children. What data structure looks like a family tree?', '["Tree","Stack","Queue","Array"]'::jsonb, 'Tree', 'A tree data structure has a root node at the top with children branching below, just like a family tree.', true),
  (gen_random_uuid(), tid, 'story', 40, 'Which data structure lets you look up a word and instantly find its meaning, like a dictionary?', '["Dictionary/Map","List","Stack","Queue"]'::jsonb, 'Dictionary/Map', 'A dictionary or map stores key-value pairs, allowing instant lookup by key, just like a real dictionary.', true),
  (gen_random_uuid(), tid, 'story', 41, 'In an array, what do we call the number used to find an item in its slot?', '["Index","Name","Label","Tag"]'::jsonb, 'Index', 'An index is the position number used to access a specific item in an array.', true),
  (gen_random_uuid(), tid, 'story', 42, 'A chain of paperclips where each clip connects to the next one is like which data structure?', '["Linked list","Array","Stack","Tree"]'::jsonb, 'Linked list', 'A linked list connects each element (node) to the next, just like paperclips chained together.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What happens when you "push" something onto a stack?', '["You add it to the top","You remove it","You search for it","You sort it"]'::jsonb, 'You add it to the top', 'Push is the operation that adds a new item to the top of the stack.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What happens when you "pop" something from a stack?', '["You remove the top item","You add an item","You find the middle","You clear the stack"]'::jsonb, 'You remove the top item', 'Pop removes and returns the top item from the stack.', true),
  (gen_random_uuid(), tid, 'story', 45, 'How do you add an item to a queue?', '["At the back (enqueue)","At the front","At the top","Anywhere you like"]'::jsonb, 'At the back (enqueue)', 'Enqueue adds an item to the rear of the queue, while dequeue removes from the front.', true),
  (gen_random_uuid(), tid, 'story', 46, 'A graph connects cities with roads. What are the cities called in graph language?', '["Nodes (vertices)","Edges","Roots","Leaves"]'::jsonb, 'Nodes (vertices)', 'In a graph, the things being connected (like cities) are called nodes or vertices.', true),
  (gen_random_uuid(), tid, 'story', 47, 'What are the lines connecting nodes in a graph called?', '["Edges","Leaves","Roots","Branches"]'::jsonb, 'Edges', 'Edges are the connections between nodes in a graph, like roads between cities.', true),
  (gen_random_uuid(), tid, 'story', 48, 'If an array has 5 items starting at index 0, what is the index of the last item?', '["4","5","1","0"]'::jsonb, '4', 'Arrays start at index 0, so with 5 items the indices are 0, 1, 2, 3, 4 — last is 4.', true),
  (gen_random_uuid(), tid, 'story', 49, 'What do we call the very first item at the top of a tree?', '["Root","Leaf","Branch","Node"]'::jsonb, 'Root', 'The root is the topmost node of a tree with no parent — the starting point of the structure.', true),
  (gen_random_uuid(), tid, 'story', 50, 'Nodes at the very bottom of a tree with no children are called what?', '["Leaves","Roots","Branches","Trunks"]'::jsonb, 'Leaves', 'Leaf nodes are at the ends of a tree — they have no children beneath them.', true),
  (gen_random_uuid(), tid, 'story', 51, 'Which data structure would you use to store your scores from all ten games in order?', '["Array","Stack","Graph","Tree"]'::jsonb, 'Array', 'An array is ideal for storing an ordered sequence of items like game scores.', true),
  (gen_random_uuid(), tid, 'story', 52, 'An empty stack has no items. If you try to pop from it, what problem occurs?', '["Underflow error","Overflow","Nothing happens","It adds an item"]'::jsonb, 'Underflow error', 'Trying to remove from an empty stack causes an underflow error — there is nothing to remove.', true),
  (gen_random_uuid(), tid, 'story', 53, 'A set of items where every item is unique (no duplicates) is called a what?', '["Set","List","Queue","Stack"]'::jsonb, 'Set', 'A set is a collection where each value appears only once — duplicates are not allowed.', true),
  (gen_random_uuid(), tid, 'story', 54, 'What is it called when you visit every node in a tree?', '["Traversal","Sorting","Searching only","Popping"]'::jsonb, 'Traversal', 'Tree traversal means visiting every node in the tree in some defined order.', true),
  (gen_random_uuid(), tid, 'story', 55, 'Which structure is best for undo actions in a drawing app (most recent action first)?', '["Stack","Queue","Array","Graph"]'::jsonb, 'Stack', 'A stack''s LIFO property makes it perfect for undo — the most recent action is removed first.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What is the time complexity of accessing an element by index in an array?', '["O(1)","O(n)","O(log n)","O(n²)"]'::jsonb, 'O(1)', 'Arrays store elements in contiguous memory, so any index can be computed and accessed in constant time.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What is the main disadvantage of a singly linked list compared to an array?', '["No random access — must traverse from the head","Uses more memory than arrays always","Cannot store strings","Has no ordering"]'::jsonb, 'No random access — must traverse from the head', 'Linked list nodes are scattered in memory; reaching element k requires traversing k nodes from the head.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'In a binary search tree, where are values smaller than the root stored?', '["In the left subtree","In the right subtree","At the root","In the leaves only"]'::jsonb, 'In the left subtree', 'BST property: left child < parent < right child, so smaller values are always in the left subtree.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'Which traversal of a BST visits nodes in ascending order?', '["In-order (left, root, right)","Pre-order (root, left, right)","Post-order (left, right, root)","Level-order"]'::jsonb, 'In-order (left, root, right)', 'In-order traversal of a BST visits the left subtree, then root, then right, yielding sorted ascending order.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What data structure is used internally by most recursive algorithms?', '["Call stack","Queue","Heap","Hash table"]'::jsonb, 'Call stack', 'Each recursive function call is added to the call stack; when it returns, the frame is popped off.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What is the worst-case time for searching in an unbalanced BST?', '["O(n)","O(log n)","O(1)","O(n log n)"]'::jsonb, 'O(n)', 'A degenerate (unbalanced) BST degrades to a linked list, making search O(n) in the worst case.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'Which data structure provides O(1) average-case lookup using key-value pairs?', '["Hash table","Array","BST","Linked list"]'::jsonb, 'Hash table', 'Hash tables use a hash function to compute index positions, giving O(1) average lookup time.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What is a collision in a hash table?', '["Two different keys hash to the same index","A node with no children","An empty array slot","An overflow error"]'::jsonb, 'Two different keys hash to the same index', 'A collision occurs when two distinct keys produce the same hash index, requiring a resolution strategy.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'Which collision resolution technique stores multiple items at the same index using a list?', '["Chaining","Open addressing","Linear probing","Quadratic probing"]'::jsonb, 'Chaining', 'Chaining maintains a linked list at each hash bucket to store all colliding elements.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What property of a heap ensures the parent is always larger than its children?', '["Max-heap property","Min-heap property","BST property","AVL property"]'::jsonb, 'Max-heap property', 'A max-heap guarantees every parent node is greater than or equal to its children.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'Which graph representation uses a 2D matrix to store edge information?', '["Adjacency matrix","Adjacency list","Edge list","Hash map"]'::jsonb, 'Adjacency matrix', 'An adjacency matrix uses an n×n grid where cell [i][j]=1 means an edge exists between nodes i and j.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is the space complexity of an adjacency matrix for a graph with V vertices?', '["O(V²)","O(V)","O(E)","O(V + E)"]'::jsonb, 'O(V²)', 'An adjacency matrix requires a V×V grid regardless of the number of edges, using O(V²) space.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'Which data structure is used to implement a priority queue efficiently?', '["Heap","Stack","Queue","Linked list"]'::jsonb, 'Heap', 'A heap provides O(log n) insertion and O(1) or O(log n) extraction of the minimum/maximum, ideal for priority queues.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'A doubly linked list differs from a singly linked list because each node has what?', '["Pointers to both next and previous nodes","Two data values","Two heads","No tail"]'::jsonb, 'Pointers to both next and previous nodes', 'Doubly linked list nodes store both a next and a previous pointer, enabling traversal in both directions.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is a circular linked list?', '["The last node points back to the first node","A list that sorts itself","A stack shaped in a circle","A list with no head"]'::jsonb, 'The last node points back to the first node', 'In a circular linked list, the tail node''s next pointer references the head, forming a loop.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'Which tree operation restores balance in an AVL tree after insertion?', '["Rotation","Deletion","Hashing","Merging"]'::jsonb, 'Rotation', 'AVL trees use single or double rotations to rebalance after insertions or deletions disturb the height balance.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is a trie used for?', '["Storing strings with shared prefixes for fast lookup","Sorting numbers","Implementing a queue","Storing graphs"]'::jsonb, 'Storing strings with shared prefixes for fast lookup', 'A trie (prefix tree) stores strings by sharing common prefixes, enabling fast search, insert, and prefix queries.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'In a min-heap, where is the smallest element always located?', '["At the root","At the leaves","At the rightmost node","In the middle"]'::jsonb, 'At the root', 'The min-heap property guarantees the root is always the smallest element in the heap.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is the time complexity of inserting into a max-heap?', '["O(log n)","O(1)","O(n)","O(n log n)"]'::jsonb, 'O(log n)', 'Heap insertion adds the element at the end and bubbles it up, taking O(log n) in the worst case.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'Which data structure would you use to check if a set of parentheses is balanced?', '["Stack","Queue","Tree","Graph"]'::jsonb, 'Stack', 'Push opening brackets; pop on closing brackets and verify matches — the stack naturally models this nesting.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the amortized time complexity of appending to a dynamic array (e.g., Python list)?', '["O(1) amortized","O(n) always","O(log n)","O(n²)"]'::jsonb, 'O(1) amortized', 'Dynamic arrays double in size when full; the cost of occasional O(n) copies is amortized to O(1) per append.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'What invariant does a Red-Black tree maintain to guarantee O(log n) operations?', '["No path from root to leaf is more than twice as long as any other such path","All leaves are at the same depth","Parent is always greater than children","No two adjacent red nodes and root is black"]'::jsonb, 'No two adjacent red nodes and root is black', 'Red-Black trees enforce coloring rules (no two consecutive red nodes, black-height equality) ensuring O(log n) height.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is the load factor in a hash table, and what threshold typically triggers resizing?', '["Number of entries divided by number of buckets; typically 0.7–0.75","Number of collisions; always 1.0","Bucket count; always 0.5","Number of deletions; 0.9"]'::jsonb, 'Number of entries divided by number of buckets; typically 0.7–0.75', 'Load factor = n/m; when it exceeds ~0.75 the table is rehashed to maintain O(1) expected performance.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'How does a B-tree differ from a binary search tree?', '["B-tree nodes can have more than two children and are optimized for disk I/O","B-trees can only store integers","B-trees have no root","B-trees are unbalanced"]'::jsonb, 'B-tree nodes can have more than two children and are optimized for disk I/O', 'B-trees use multi-way branching to minimize tree height and disk reads, making them ideal for databases.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is the difference between a graph and a tree in terms of structure?', '["A tree is a connected acyclic graph; a graph may have cycles and disconnected components","They are the same","A graph has a root; a tree does not","Trees have edges; graphs have nodes only"]'::jsonb, 'A tree is a connected acyclic graph; a graph may have cycles and disconnected components', 'Trees are special graphs — connected, undirected, acyclic — with exactly V-1 edges for V nodes.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'Which data structure supports O(log n) rank and select operations on ordered sets?', '["Order-statistic tree","Hash table","Min-heap","Unordered set"]'::jsonb, 'Order-statistic tree', 'An order-statistic tree augments a BST with subtree sizes, enabling efficient rank (position) and select (k-th element) queries.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is the primary use case for a Bloom filter?', '["Probabilistic set membership testing with no false negatives but possible false positives","Exact set membership","Sorting strings","Graph traversal"]'::jsonb, 'Probabilistic set membership testing with no false negatives but possible false positives', 'Bloom filters use multiple hash functions and a bit array for space-efficient approximate set membership.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What is cache-oblivious data structure design?', '["Designs that achieve optimal cache performance at all memory hierarchy levels without knowing cache parameters","Designs that ignore caching","Structures that only work in RAM","Algorithms without loops"]'::jsonb, 'Designs that achieve optimal cache performance at all memory hierarchy levels without knowing cache parameters', 'Cache-oblivious structures like van Emde Boas layout optimally exploit cache without parameterizing on cache line size.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is a skip list and what is its average search complexity?', '["A probabilistic linked list with multiple forward pointers; O(log n) average search","A sorted array with O(1) search","A hash table variant; O(1)","A tree with skipped nodes; O(n)"]'::jsonb, 'A probabilistic linked list with multiple forward pointers; O(log n) average search', 'Skip lists add express lanes of increasing step size, providing O(log n) expected search without tree rotations.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'In a segment tree, what operation can be performed in O(log n) time?', '["Range queries and point updates","Only point lookups","Full array sorting","Graph shortest path"]'::jsonb, 'Range queries and point updates', 'Segment trees partition ranges into segments, supporting sum/min/max range queries and updates in O(log n).', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is a Fenwick tree (Binary Indexed Tree) optimized for?', '["Prefix sum queries and point updates in O(log n)","Full range updates only","Hash collision resolution","Tree balancing"]'::jsonb, 'Prefix sum queries and point updates in O(log n)', 'Fenwick trees use bit manipulation to store partial sums, enabling O(log n) prefix sum queries and updates with minimal space.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'Why are open-addressing hash tables often faster in practice than chaining despite similar asymptotic complexity?', '["Better cache locality — data stays in contiguous memory","They have fewer collisions mathematically","They use less code","They do not need a hash function"]'::jsonb, 'Better cache locality — data stays in contiguous memory', 'Open addressing keeps all data in a single array, improving CPU cache hit rates compared to pointer-based chaining.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is a disjoint-set (union-find) data structure used for?', '["Tracking connected components and supporting union/find in near O(1) amortized with path compression","Sorting elements","Implementing a priority queue","Storing key-value pairs"]'::jsonb, 'Tracking connected components and supporting union/find in near O(1) amortized with path compression', 'Union-find with path compression and union by rank achieves nearly O(1) amortized per operation, used in Kruskal''s algorithm.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is the worst-case time complexity of a hash table operation with poor hash function (all keys collide)?', '["O(n)","O(1)","O(log n)","O(n log n)"]'::jsonb, 'O(n)', 'If all keys hash to the same bucket, every operation must scan the full chain, degrading to O(n).', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'How does a van Emde Boas tree achieve O(log log U) operations for universe size U?', '["Recursive decomposition into sqrt(U)-sized clusters with a summary structure","By using hash functions","By sorting elements first","By using balanced BST internally"]'::jsonb, 'Recursive decomposition into sqrt(U)-sized clusters with a summary structure', 'vEB trees recursively split keys across clusters of size √U with a summary, giving log log U recursion depth.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What distinguishes a DAG (Directed Acyclic Graph) from a general directed graph?', '["A DAG has no directed cycles","A DAG has no edges","A DAG is always a tree","A DAG has weighted edges only"]'::jsonb, 'A DAG has no directed cycles', 'A DAG is a directed graph with no path that loops back to its starting node, enabling topological sorting.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'In a rope data structure, what operation is O(log n) that would be O(n) in a string?', '["Concatenation and split","Character access","Search","Sorting"]'::jsonb, 'Concatenation and split', 'Ropes represent strings as binary trees of substrings, making concatenation and split O(log n) instead of O(n).', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What is the height of a complete binary tree with n nodes?', '["O(log n)","O(n)","O(n²)","O(1)"]'::jsonb, 'O(log n)', 'A complete binary tree fills levels from left to right; n nodes give height floor(log₂ n), which is O(log n).', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'Which advanced tree structure is used in Linux kernel for memory management and interval scheduling?', '["Red-Black tree","AVL tree","Splay tree","Trie"]'::jsonb, 'Red-Black tree', 'The Linux kernel uses Red-Black trees for virtual memory areas and scheduling due to their guaranteed O(log n) operations.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is a persistent data structure?', '["One that preserves all previous versions after modifications","One stored on disk","One that never changes","One with no deletions"]'::jsonb, 'One that preserves all previous versions after modifications', 'Persistent (immutable) data structures use structural sharing to maintain all historical versions efficiently.', true);
END;
$$;

-- ============================================================
-- TOPIC 4: Machine Learning Basics
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Machine Learning Basics' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'When a computer learns from examples, like learning animal names from pictures, what is that called?', '["Machine learning","Magic","Memorizing","Guessing"]'::jsonb, 'Machine learning', 'Machine learning is when computers learn patterns from examples rather than following fixed rules.', true),
  (gen_random_uuid(), tid, 'story', 37, 'If you show a computer many pictures of cats and dogs and it learns to tell them apart, what has it done?', '["Learned to classify","Learned to draw","Learned to count","Learned to sing"]'::jsonb, 'Learned to classify', 'Classification is when a machine learning model sorts things into categories like "cat" or "dog."', true),
  (gen_random_uuid(), tid, 'story', 38, 'What do we call the examples we give a computer to help it learn?', '["Training data","Secret data","Wrong data","Empty data"]'::jsonb, 'Training data', 'Training data is the set of examples used to teach a machine learning model.', true),
  (gen_random_uuid(), tid, 'story', 39, 'After a computer learns, how do we check if it learned correctly?', '["Test it with new examples it has not seen","Ask it questions about history","Give it more training data","Delete its memory"]'::jsonb, 'Test it with new examples it has not seen', 'We use a test set — new examples the model has never seen — to check how well it really learned.', true),
  (gen_random_uuid(), tid, 'story', 40, 'A model that guesses "cat" for every picture, even dogs, has learned what?', '["Nothing useful — it is not learning the difference","Everything perfectly","Only to see cats","The meaning of dogs"]'::jsonb, 'Nothing useful — it is not learning the difference', 'A model that always picks one class has not learned to distinguish between classes.', true),
  (gen_random_uuid(), tid, 'story', 41, 'What is a "label" in machine learning?', '["The correct answer attached to a training example","A sticker on the computer","The name of the model","A type of data"]'::jsonb, 'The correct answer attached to a training example', 'A label tells the model what the right answer is for each training example, like "cat" or "dog."', true),
  (gen_random_uuid(), tid, 'story', 42, 'When a model does great on training data but fails on new data, we say it has done what?', '["Overfit","Underfit","Learned perfectly","Been tested"]'::jsonb, 'Overfit', 'Overfitting means the model memorized training examples instead of learning general patterns.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What type of learning has labeled examples with correct answers?', '["Supervised learning","Unsupervised learning","Random learning","Secret learning"]'::jsonb, 'Supervised learning', 'Supervised learning trains on labeled examples where the correct output is provided for every input.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What type of learning finds patterns without being told the correct answers?', '["Unsupervised learning","Supervised learning","Forced learning","Simple learning"]'::jsonb, 'Unsupervised learning', 'Unsupervised learning finds hidden patterns or groupings in data without any labels.', true),
  (gen_random_uuid(), tid, 'story', 45, 'A model predicts tomorrow''s temperature as a number. Is this classification or regression?', '["Regression","Classification","Sorting","Grouping"]'::jsonb, 'Regression', 'Regression predicts a continuous number (like temperature), while classification predicts a category.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What do we call it when a model groups similar things together without labels?', '["Clustering","Labeling","Sorting alphabetically","Classifying"]'::jsonb, 'Clustering', 'Clustering is an unsupervised technique that groups similar data points together.', true),
  (gen_random_uuid(), tid, 'story', 47, 'If a spam filter blocks important emails and lets spam through, what might be wrong?', '["It was trained on bad examples","It is too fast","It uses too much memory","It has too many rules"]'::jsonb, 'It was trained on bad examples', 'Poor training data leads to poor model performance — garbage in, garbage out.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What does "accuracy" measure in a machine learning model?', '["How often it gets the right answer","How fast it runs","How big it is","How much data it used"]'::jsonb, 'How often it gets the right answer', 'Accuracy is the percentage of predictions the model gets correct out of all predictions made.', true),
  (gen_random_uuid(), tid, 'story', 49, 'What is a "feature" in machine learning?', '["A piece of information about an example, like height or color","A type of computer","A label","A reward"]'::jsonb, 'A piece of information about an example, like height or color', 'Features are the measurable properties of data used as inputs to a machine learning model.', true),
  (gen_random_uuid(), tid, 'story', 50, 'A robot that gets a reward for correct actions and a penalty for wrong ones is using what kind of learning?', '["Reinforcement learning","Supervised learning","Unsupervised learning","Clustering"]'::jsonb, 'Reinforcement learning', 'Reinforcement learning trains agents through rewards and penalties based on their actions in an environment.', true),
  (gen_random_uuid(), tid, 'story', 51, 'What is the simplest way to describe a machine learning model?', '["A mathematical pattern learned from data to make predictions","A very smart robot","A database","A calculator"]'::jsonb, 'A mathematical pattern learned from data to make predictions', 'A model is the learned mathematical function mapping inputs to outputs after training on data.', true),
  (gen_random_uuid(), tid, 'story', 52, 'If you split your data into training and testing parts, why should they never overlap?', '["So the model is tested on data it has never seen","To save memory","Because computers prefer it","Labels get mixed up"]'::jsonb, 'So the model is tested on data it has never seen', 'Testing on unseen data gives an honest measure of how well the model generalizes to new situations.', true),
  (gen_random_uuid(), tid, 'story', 53, 'What does it mean when a model "predicts"?', '["It makes a guess about new data based on what it learned","It draws a picture","It deletes old data","It counts items"]'::jsonb, 'It makes a guess about new data based on what it learned', 'Prediction is applying the learned model to new, unseen inputs to produce an output.', true),
  (gen_random_uuid(), tid, 'story', 54, 'Why do we need a lot of training examples for a machine learning model?', '["More examples help the model learn better patterns","Computers get lonely","To slow down the computer","To fill up memory"]'::jsonb, 'More examples help the model learn better patterns', 'More diverse training examples help the model learn general patterns rather than memorizing specific cases.', true),
  (gen_random_uuid(), tid, 'story', 55, 'What is a decision tree in machine learning?', '["A model that makes decisions by asking yes/no questions","A real tree made of data","A chart of training data","A type of neural network"]'::jsonb, 'A model that makes decisions by asking yes/no questions', 'A decision tree splits data using a series of yes/no questions about features to make predictions.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What is the purpose of a validation set in machine learning?', '["To tune hyperparameters and monitor training without touching the test set","To train the model","To label data","To store features"]'::jsonb, 'To tune hyperparameters and monitor training without touching the test set', 'The validation set is a held-out portion used during training to select hyperparameters and detect overfitting.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What is the difference between a parameter and a hyperparameter?', '["Parameters are learned from data; hyperparameters are set before training","They are the same","Hyperparameters are always integers","Parameters control learning rate only"]'::jsonb, 'Parameters are learned from data; hyperparameters are set before training', 'Model parameters (weights) are learned during training; hyperparameters (like learning rate) are configured beforehand.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What does the bias-variance tradeoff describe?', '["The tension between underfitting (high bias) and overfitting (high variance)","Memory vs speed","Training time vs accuracy","Data size vs model size"]'::jsonb, 'The tension between underfitting (high bias) and overfitting (high variance)', 'High bias means the model is too simple (underfits); high variance means it overfits — balancing both is key.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'Which metric is better than accuracy when dealing with imbalanced classes?', '["F1 score","Accuracy","Loss","Precision alone"]'::jsonb, 'F1 score', 'F1 score (harmonic mean of precision and recall) is more informative than accuracy on imbalanced datasets.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is k-fold cross-validation?', '["Splitting data into k parts, training on k-1 and validating on 1, rotating k times","Training k separate models","Using k features only","Repeating training k times on the same data"]'::jsonb, 'Splitting data into k parts, training on k-1 and validating on 1, rotating k times', 'K-fold cross-validation rotates the validation fold across all k splits, giving a robust performance estimate.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What is regularization in machine learning?', '["A technique to prevent overfitting by penalizing model complexity","A way to speed up training","A data preprocessing step","A type of activation function"]'::jsonb, 'A technique to prevent overfitting by penalizing model complexity', 'Regularization (L1/L2) adds a penalty term to the loss function, discouraging overly complex models.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'In a confusion matrix, what does "false positive" mean?', '["The model predicted positive but the true label was negative","The model was correct","The model predicted negative incorrectly","A training error"]'::jsonb, 'The model predicted positive but the true label was negative', 'A false positive (Type I error) occurs when the model incorrectly predicts the positive class.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'Which algorithm finds the hyperplane that maximally separates two classes?', '["Support Vector Machine (SVM)","Decision tree","K-means","Naive Bayes"]'::jsonb, 'Support Vector Machine (SVM)', 'SVMs find the maximum-margin hyperplane that best separates classes in feature space.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What does the learning rate control in gradient descent?', '["How large a step the algorithm takes when updating parameters","The number of training examples","The model architecture","The test set size"]'::jsonb, 'How large a step the algorithm takes when updating parameters', 'Learning rate determines step size in the direction of the gradient; too large overshoots, too small is slow.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is feature scaling and why is it important?', '["Normalizing features to similar ranges so gradient descent converges faster","Adding more features","Removing irrelevant features","Doubling the dataset"]'::jsonb, 'Normalizing features to similar ranges so gradient descent converges faster', 'Feature scaling (e.g., standardization) prevents features with large values from dominating gradient updates.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What does K-means clustering try to minimize?', '["Within-cluster sum of squared distances to centroids","Number of clusters","Training time","Feature count"]'::jsonb, 'Within-cluster sum of squared distances to centroids', 'K-means minimizes inertia (sum of squared distances from each point to its assigned cluster centroid).', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is the purpose of the loss function in machine learning?', '["To measure how wrong the model''s predictions are","To add features","To split data","To choose hyperparameters"]'::jsonb, 'To measure how wrong the model''s predictions are', 'The loss function quantifies prediction error; training minimizes this function to improve the model.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is gradient descent?', '["An optimization algorithm that iteratively adjusts parameters to minimize the loss","A data cleaning technique","A type of decision tree","A clustering method"]'::jsonb, 'An optimization algorithm that iteratively adjusts parameters to minimize the loss', 'Gradient descent follows the negative gradient of the loss function to find parameter values that minimize loss.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'Which ensemble method trains many decision trees on random data subsets?', '["Random Forest","AdaBoost","Gradient Boosting","Bagging only"]'::jsonb, 'Random Forest', 'Random Forest builds many trees on bootstrapped subsets with random feature selection, then averages predictions.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is the "curse of dimensionality"?', '["As dimensions increase, data becomes sparse and distances lose meaning","More features always help","High-dimensional data is easier to visualize","Dimensionality reduces accuracy always"]'::jsonb, 'As dimensions increase, data becomes sparse and distances lose meaning', 'In high dimensions, data points are far apart and distance metrics lose discriminative power.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is the elbow method used for in K-means?', '["Selecting the optimal number of clusters by plotting inertia vs k","Splitting data","Choosing learning rate","Selecting features"]'::jsonb, 'Selecting the optimal number of clusters by plotting inertia vs k', 'The elbow method plots inertia vs number of clusters; the "elbow" point indicates diminishing returns.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What does PCA (Principal Component Analysis) do?', '["Reduces dimensionality by finding directions of maximum variance","Increases features","Classifies data","Builds decision trees"]'::jsonb, 'Reduces dimensionality by finding directions of maximum variance', 'PCA projects data onto orthogonal axes (principal components) that capture the most variance, reducing dimensions.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What is the difference between precision and recall?', '["Precision: correct positives / predicted positives; recall: correct positives / actual positives","They are the same metric","Precision uses the test set; recall uses training","Recall only applies to regression"]'::jsonb, 'Precision: correct positives / predicted positives; recall: correct positives / actual positives', 'Precision measures prediction quality; recall measures how many true positives are found.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is transfer learning?', '["Using a model trained on one task as a starting point for a different task","Training from scratch","Copying training data","Using the test set for training"]'::jsonb, 'Using a model trained on one task as a starting point for a different task', 'Transfer learning leverages knowledge from pre-trained models, reducing data and compute needed for new tasks.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What does "underfitting" mean?', '["The model is too simple and misses patterns in training data","The model memorized training data","The model has too many parameters","The model is too slow"]'::jsonb, 'The model is too simple and misses patterns in training data', 'Underfitting occurs when a model lacks sufficient complexity to capture the underlying data patterns.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the VC dimension and why is it important in statistical learning theory?', '["A measure of model capacity; bounds generalization error via the VC inequality","The number of training examples needed","The optimal learning rate","The number of layers in a neural network"]'::jsonb, 'A measure of model capacity; bounds generalization error via the VC inequality', 'VC dimension quantifies hypothesis space complexity; the VC inequality bounds test error as a function of sample size and VC dim.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'What is the PAC learning framework?', '["Probably Approximately Correct — bounds the number of samples needed to learn a concept with high probability","Partial Approximation Clustering","Polynomial Accuracy Classifier","Pre-trained Attention Computation"]'::jsonb, 'Probably Approximately Correct — bounds the number of samples needed to learn a concept with high probability', 'PAC learning formalizes learnability by specifying error ε and confidence δ, bounding required sample size.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'In the context of SVMs, what is the kernel trick?', '["Implicitly mapping data to high-dimensional space using a kernel function without computing the mapping explicitly","Adding polynomial features manually","A regularization method","A hyperparameter search strategy"]'::jsonb, 'Implicitly mapping data to high-dimensional space using a kernel function without computing the mapping explicitly', 'Kernel functions compute inner products in high-dimensional feature space efficiently, enabling non-linear SVMs.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'What is the difference between bagging and boosting ensemble methods?', '["Bagging trains models independently in parallel; boosting trains sequentially with each correcting prior errors","They are identical","Bagging only works with trees; boosting works with any model","Boosting uses less data"]'::jsonb, 'Bagging trains models independently in parallel; boosting trains sequentially with each correcting prior errors', 'Bagging reduces variance through averaging; boosting reduces bias by iteratively reweighting misclassified examples.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is XGBoost''s key advantage over standard gradient boosting?', '["Regularized objective, parallel tree construction, and handling missing values natively","Only faster initialization","Uses neural networks internally","Requires no hyperparameter tuning"]'::jsonb, 'Regularized objective, parallel tree construction, and handling missing values natively', 'XGBoost adds L1/L2 regularization to gradient boosting and exploits cache-aware parallel tree building.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What does the No Free Lunch theorem state?', '["No single algorithm performs best on all problems — average performance is equal across all algorithms","Gradient descent always finds the global minimum","More data always helps","Deep learning is always best"]'::jsonb, 'No single algorithm performs best on all problems — average performance is equal across all algorithms', 'The NFL theorem proves that averaged over all possible problems, every algorithm has the same expected performance.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'In Gaussian Naive Bayes, what assumption is made about features?', '["Features are conditionally independent given the class and follow Gaussian distributions","Features are correlated","Features must be binary","Features are always normalized"]'::jsonb, 'Features are conditionally independent given the class and follow Gaussian distributions', 'Naive Bayes assumes conditional independence of features and models each with a class-conditional Gaussian.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What is the empirical risk minimization (ERM) principle?', '["Choosing the hypothesis that minimizes average loss on the training set","Minimizing validation loss only","Maximizing margin","Minimizing model complexity"]'::jsonb, 'Choosing the hypothesis that minimizes average loss on the training set', 'ERM selects the model that minimizes training error, forming the basis of most supervised learning algorithms.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is label smoothing and why is it used?', '["Replacing hard 0/1 labels with soft values (e.g., 0.9/0.1) to prevent overconfidence","Adding noise to features","Smoothing the loss curve","A regularization for regression"]'::jsonb, 'Replacing hard 0/1 labels with soft values (e.g., 0.9/0.1) to prevent overconfidence', 'Label smoothing regularizes classifiers by softening hard labels, improving calibration and generalization.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is the Gini impurity used for in decision tree learning?', '["Measuring node impurity to select the best feature split","Computing gradient descent steps","Evaluating regression output","Selecting hyperparameters"]'::jsonb, 'Measuring node impurity to select the best feature split', 'Gini impurity measures class mixing in a node; the split that minimizes weighted child impurity is chosen.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'How does SMOTE address class imbalance?', '["Synthetically generating minority class examples by interpolating between existing ones","Deleting majority class examples","Resampling with replacement","Changing the loss function only"]'::jsonb, 'Synthetically generating minority class examples by interpolating between existing ones', 'SMOTE creates new synthetic minority samples along line segments between existing minority neighbors.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is the difference between L1 and L2 regularization effects on model weights?', '["L1 produces sparse weights (some zero); L2 shrinks all weights toward zero uniformly","L1 is always better","L2 creates sparse solutions","They have identical effects"]'::jsonb, 'L1 produces sparse weights (some zero); L2 shrinks all weights toward zero uniformly', 'L1 (Lasso) encourages sparsity via absolute value penalty; L2 (Ridge) shrinks all weights smoothly.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is online learning versus batch learning?', '["Online updates the model with each new example; batch retrains on the full dataset","They are the same","Online learning requires more memory","Batch learning is always faster"]'::jsonb, 'Online updates the model with each new example; batch retrains on the full dataset', 'Online learning adapts incrementally to streaming data; batch learning processes all data each training cycle.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is isotonic regression used for?', '["Fitting a non-decreasing piecewise constant function to data; used in probability calibration","Multi-class classification","Feature scaling","Dimensionality reduction"]'::jsonb, 'Fitting a non-decreasing piecewise constant function to data; used in probability calibration', 'Isotonic regression fits monotone functions and is commonly used to calibrate classifier output probabilities.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'How does mini-batch gradient descent differ from stochastic and full-batch gradient descent?', '["Mini-batch uses a small subset per update, balancing noise reduction and computational efficiency","Mini-batch is identical to stochastic","Mini-batch always uses exactly 32 samples","Mini-batch requires more epochs always"]'::jsonb, 'Mini-batch uses a small subset per update, balancing noise reduction and computational efficiency', 'Mini-batch (e.g., 32–256 samples) offers a practical tradeoff: noisier than full-batch but faster and more stable than pure SGD.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What is the purpose of the softmax function in multi-class classification?', '["Converting raw logits to a probability distribution summing to 1","Computing gradients","Regularizing weights","Selecting the learning rate"]'::jsonb, 'Converting raw logits to a probability distribution summing to 1', 'Softmax exponentiates and normalizes logits so they form valid probabilities for each class.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is mutual information and how is it used in feature selection?', '["Measures statistical dependence between feature and target; high MI indicates a useful feature","Measures Euclidean distance","Computes training loss","Determines cluster count"]'::jsonb, 'Measures statistical dependence between feature and target; high MI indicates a useful feature', 'Mutual information quantifies how much knowing a feature reduces uncertainty about the label.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What does a ROC curve plot and what does AUC-ROC measure?', '["True positive rate vs false positive rate; AUC measures discrimination ability across all thresholds","Accuracy vs loss; AUC measures training speed","Precision vs recall; same as F1","Feature importance vs model size"]'::jsonb, 'True positive rate vs false positive rate; AUC measures discrimination ability across all thresholds', 'ROC curves visualize classifier performance at all thresholds; AUC = 1 is perfect, 0.5 is random.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What is the expectation-maximization (EM) algorithm used for?', '["Finding maximum likelihood estimates when data has latent (hidden) variables","Minimizing classification error directly","Building decision trees","Implementing SVMs"]'::jsonb, 'Finding maximum likelihood estimates when data has latent (hidden) variables', 'EM alternates between estimating latent variables (E-step) and maximizing likelihood (M-step) until convergence.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'Why can collinearity of features cause problems in linear regression?', '["It makes the coefficient estimates unstable and inflates their variance","It always reduces accuracy","It prevents gradient descent from running","It causes overfitting only in trees"]'::jsonb, 'It makes the coefficient estimates unstable and inflates their variance', 'Highly correlated features make the design matrix near-singular, causing large, unreliable regression coefficients.', true);
END;
$$;

-- ============================================================
-- TOPIC 5: Neural Networks
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Neural Networks' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'A neural network is inspired by what part of the human body?', '["The brain","The heart","The eyes","The hands"]'::jsonb, 'The brain', 'Neural networks are modeled after the brain''s interconnected neurons that send signals to each other.', true),
  (gen_random_uuid(), tid, 'story', 37, 'What do we call the tiny processing units in a neural network, inspired by brain cells?', '["Neurons (nodes)","Pixels","Buttons","Wires"]'::jsonb, 'Neurons (nodes)', 'Artificial neurons are the basic units of a neural network, inspired by biological brain cells.', true),
  (gen_random_uuid(), tid, 'story', 38, 'In a neural network, how do neurons share information?', '["Through connections called weights","By shouting","Through emails","By sorting data"]'::jsonb, 'Through connections called weights', 'Neurons are linked by weighted connections; the strength of each connection determines how much influence one neuron has on another.', true),
  (gen_random_uuid(), tid, 'story', 39, 'The first layer of a neural network that receives the raw data is called what?', '["Input layer","Output layer","Hidden layer","Middle layer"]'::jsonb, 'Input layer', 'The input layer is the first layer that receives the raw features of the data being processed.', true),
  (gen_random_uuid(), tid, 'story', 40, 'The last layer that gives the final answer is called what?', '["Output layer","Input layer","Hidden layer","Secret layer"]'::jsonb, 'Output layer', 'The output layer produces the network''s final prediction or answer.', true),
  (gen_random_uuid(), tid, 'story', 41, 'Layers between the input and output in a neural network are called what?', '["Hidden layers","Middle layers","Extra layers","Bonus layers"]'::jsonb, 'Hidden layers', 'Hidden layers process information between the input and output, learning complex patterns.', true),
  (gen_random_uuid(), tid, 'story', 42, 'A network with many hidden layers is called what?', '["Deep neural network","Shallow network","Wide network","Flat network"]'::jsonb, 'Deep neural network', 'Deep learning refers to neural networks with many (deep) hidden layers that learn hierarchical features.', true),
  (gen_random_uuid(), tid, 'story', 43, 'When a neural network makes a mistake, how does it learn to do better?', '["By adjusting the connection weights","By deleting neurons","By starting over","By asking a human"]'::jsonb, 'By adjusting the connection weights', 'Backpropagation adjusts weights based on errors, gradually improving the network''s predictions.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What do we call the number of times a neural network trains on the full dataset?', '["Epochs","Rounds","Chapters","Steps"]'::jsonb, 'Epochs', 'An epoch is one complete pass through the entire training dataset during the learning process.', true),
  (gen_random_uuid(), tid, 'story', 45, 'If a neural network is very confident but always wrong, what might be the problem?', '["It is overfitting or has bad training data","It is thinking too hard","It needs more neurons","It is too shallow"]'::jsonb, 'It is overfitting or has bad training data', 'High confidence with wrong answers often indicates overfitting to training data or systematic bias in training examples.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What is the function that a neuron uses to decide whether to "fire" or pass information on?', '["Activation function","Sleep function","Memory function","Display function"]'::jsonb, 'Activation function', 'An activation function determines whether and how strongly a neuron passes its signal to the next layer.', true),
  (gen_random_uuid(), tid, 'story', 47, 'Which simple activation function outputs 0 for negative inputs and the input value for positive inputs?', '["ReLU","Sigmoid","Tanh","Softmax"]'::jsonb, 'ReLU', 'ReLU (Rectified Linear Unit) outputs max(0, x) — zero for negatives, the input value for positives.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What kind of neural network is especially good at understanding images?', '["Convolutional Neural Network (CNN)","Recurrent Neural Network (RNN)","Simple perceptron","Random forest"]'::jsonb, 'Convolutional Neural Network (CNN)', 'CNNs use convolutional filters to detect spatial patterns like edges and shapes in images.', true),
  (gen_random_uuid(), tid, 'story', 49, 'What kind of neural network is good at understanding sequences like sentences?', '["Recurrent Neural Network (RNN)","CNN","Perceptron","Clustering network"]'::jsonb, 'Recurrent Neural Network (RNN)', 'RNNs have loops that pass information from one step to the next, making them suited for sequential data.', true),
  (gen_random_uuid(), tid, 'story', 50, 'What does "training" a neural network mean?', '["Showing it many examples so it adjusts its weights to make better predictions","Giving it a name","Turning it on for the first time","Deleting old data"]'::jsonb, 'Showing it many examples so it adjusts its weights to make better predictions', 'Training is the process of feeding data to the network and updating weights to minimize prediction errors.', true),
  (gen_random_uuid(), tid, 'story', 51, 'What is a bias in a neural network (not fairness bias)?', '["An extra number added to a neuron''s calculation to shift its output","A mistake in the data","A type of hidden layer","A learning rate"]'::jsonb, 'An extra number added to a neuron''s calculation to shift its output', 'A bias term allows a neuron to shift its activation threshold, making the network more flexible.', true),
  (gen_random_uuid(), tid, 'story', 52, 'What happens to a neural network''s accuracy as training continues over many epochs?', '["It generally improves, then may overfit if trained too long","It always gets worse","It stays exactly the same","It randomly changes"]'::jsonb, 'It generally improves, then may overfit if trained too long', 'Accuracy typically improves with training but can degrade on new data if the network overfits.', true),
  (gen_random_uuid(), tid, 'story', 53, 'What is a weight in a neural network?', '["A number that controls how strongly one neuron influences another","The size of the network","The number of layers","The training speed"]'::jsonb, 'A number that controls how strongly one neuron influences another', 'Weights are the learnable parameters that scale signals passed between neurons in the network.', true),
  (gen_random_uuid(), tid, 'story', 54, 'If you show a neural network a picture it has never seen before, what is that called?', '["Inference (prediction)","Training","Testing the wrong way","Overfitting"]'::jsonb, 'Inference (prediction)', 'Inference is using a trained neural network to make predictions on new, unseen data.', true),
  (gen_random_uuid(), tid, 'story', 55, 'What is the most basic type of neural network with only an input and output layer?', '["Perceptron","Deep network","CNN","RNN"]'::jsonb, 'Perceptron', 'A perceptron is the simplest neural network — a single layer mapping inputs directly to output.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What problem does the vanishing gradient problem cause in deep networks?', '["Gradients become extremely small in early layers, stopping effective learning","The network grows too large","Weights become too large","Training becomes too fast"]'::jsonb, 'Gradients become extremely small in early layers, stopping effective learning', 'During backpropagation, gradients can shrink exponentially through many layers, preventing early layers from updating.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'How does ReLU help solve the vanishing gradient problem?', '["Its gradient is 1 for positive inputs, preventing shrinkage","Its gradient is always 0","It uses tanh internally","It clips all gradients"]'::jsonb, 'Its gradient is 1 for positive inputs, preventing shrinkage', 'ReLU''s constant gradient of 1 for positive values avoids the exponential gradient shrinkage of sigmoid/tanh.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What is dropout in neural networks?', '["Randomly setting some neuron outputs to zero during training to prevent overfitting","Removing entire layers","Reducing learning rate","Deleting training data"]'::jsonb, 'Randomly setting some neuron outputs to zero during training to prevent overfitting', 'Dropout randomly zeroes neurons during training, forcing the network to learn redundant representations.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What does batch normalization do?', '["Normalizes layer inputs to speed up training and improve stability","Increases the batch size","Normalizes the training data only","Sorts neurons"]'::jsonb, 'Normalizes layer inputs to speed up training and improve stability', 'Batch normalization rescales and shifts layer activations to have zero mean and unit variance per mini-batch.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is the purpose of the softmax activation in the output layer for multi-class problems?', '["Converting logits to class probabilities that sum to 1","Making outputs negative","Selecting the largest neuron","Applying dropout"]'::jsonb, 'Converting logits to class probabilities that sum to 1', 'Softmax exponentiates and normalizes output neuron values into a probability distribution over classes.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What is backpropagation?', '["Computing gradients of the loss with respect to weights using the chain rule, then updating weights","A forward pass through the network","A type of regularization","A learning rate schedule"]'::jsonb, 'Computing gradients of the loss with respect to weights using the chain rule, then updating weights', 'Backpropagation applies the chain rule to propagate error gradients backward through the network for weight updates.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What does a convolutional filter (kernel) detect in a CNN?', '["Local spatial patterns like edges, textures, or shapes","Full image labels","Random noise","Text in images"]'::jsonb, 'Local spatial patterns like edges, textures, or shapes', 'CNN filters slide over the input and detect local spatial features; early layers find edges, deeper layers find complex shapes.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What is pooling in a CNN used for?', '["Reducing spatial dimensions while retaining important features","Adding more filters","Increasing image resolution","Computing gradients"]'::jsonb, 'Reducing spatial dimensions while retaining important features', 'Pooling (e.g., max pooling) downsamples feature maps, reducing computation and adding translation invariance.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is an LSTM and what problem does it solve?', '["Long Short-Term Memory — an RNN variant that can learn long-range dependencies without vanishing gradients","A type of CNN","A feed-forward network","A pooling method"]'::jsonb, 'Long Short-Term Memory — an RNN variant that can learn long-range dependencies without vanishing gradients', 'LSTMs use gating mechanisms (input, forget, output gates) to selectively retain or discard information over long sequences.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is weight initialization and why does it matter?', '["Setting initial weight values to enable stable gradient flow from the start","Saving weights after training","Resetting weights during training","Choosing the activation function"]'::jsonb, 'Setting initial weight values to enable stable gradient flow from the start', 'Poor initialization (all zeros or too large) causes vanishing/exploding gradients; methods like Xavier/He init prevent this.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What is transfer learning in the context of neural networks?', '["Reusing a pre-trained network''s weights as a starting point for a new task","Training from random weights","Using a network on the same task","Copying architecture only"]'::jsonb, 'Reusing a pre-trained network''s weights as a starting point for a new task', 'Transfer learning fine-tunes a pre-trained network on a new dataset, requiring much less data and compute.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is the exploding gradient problem?', '["Gradients grow exponentially large, causing unstable weight updates","Gradients disappear in early layers","The network has too many layers","The learning rate is too small"]'::jsonb, 'Gradients grow exponentially large, causing unstable weight updates', 'Exploding gradients cause weight updates to be so large the network becomes numerically unstable; gradient clipping helps.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What does the Adam optimizer improve over plain gradient descent?', '["Adapts the learning rate per parameter using first and second moment estimates","Uses a fixed learning rate","Ignores gradients for some weights","Always converges to the global minimum"]'::jsonb, 'Adapts the learning rate per parameter using first and second moment estimates', 'Adam combines momentum (first moment) and RMSProp (second moment) for adaptive, efficient optimization.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What is an autoencoder used for?', '["Learning compressed representations of data by encoding and reconstructing it","Classifying images","Generating text","Performing regression"]'::jsonb, 'Learning compressed representations of data by encoding and reconstructing it', 'Autoencoders compress input to a bottleneck (encoder) then reconstruct it (decoder), learning efficient representations.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is the role of the flatten layer in a CNN before fully connected layers?', '["Converting 2D feature maps to a 1D vector for the dense layers","Adding more filters","Performing pooling","Computing the loss"]'::jsonb, 'Converting 2D feature maps to a 1D vector for the dense layers', 'Flattening reshapes the 3D convolutional output into a 1D vector so fully connected layers can process it.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is a GAN (Generative Adversarial Network)?', '["Two networks — a generator and discriminator — that compete to produce realistic data","A type of CNN","A recurrent network for games","A classification network"]'::jsonb, 'Two networks — a generator and discriminator — that compete to produce realistic data', 'In a GAN, the generator creates fake data and the discriminator tries to detect it, improving each other.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is the cross-entropy loss function used for?', '["Measuring the difference between predicted probabilities and true class labels","Computing mean squared error","Measuring accuracy","Selecting features"]'::jsonb, 'Measuring the difference between predicted probabilities and true class labels', 'Cross-entropy loss penalizes confident wrong predictions heavily, making it ideal for classification tasks.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What does "fine-tuning" a pre-trained model mean?', '["Continuing training on a new dataset with a small learning rate to adapt weights","Training only the last layer","Freezing all weights","Changing the architecture"]'::jsonb, 'Continuing training on a new dataset with a small learning rate to adapt weights', 'Fine-tuning updates some or all pre-trained weights on new data, preserving learned features while adapting to the new task.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is the receptive field of a neuron in a CNN?', '["The region of the input image that influences that neuron''s activation","The number of filters","The pooling window size","The dropout rate"]'::jsonb, 'The region of the input image that influences that neuron''s activation', 'The receptive field is the area of the original image that a particular neuron can "see" through its layer stack.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What is residual learning (ResNet) and what problem does it address?', '["Adding skip connections so gradients can flow directly through layers, addressing degradation in very deep networks","A pooling technique","A regularization method","A loss function"]'::jsonb, 'Adding skip connections so gradients can flow directly through layers, addressing degradation in very deep networks', 'ResNets add shortcut connections that bypass layers, letting gradients flow freely and enabling training of very deep networks.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the universal approximation theorem?', '["A neural network with one hidden layer and sufficient neurons can approximate any continuous function arbitrarily well","All neural networks converge","Deep networks are always better than shallow ones","Backpropagation always finds the global minimum"]'::jsonb, 'A neural network with one hidden layer and sufficient neurons can approximate any continuous function arbitrarily well', 'The UAT guarantees representational power but says nothing about efficiency of learning or generalization.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'How does the attention mechanism in Transformers differ from RNN sequential processing?', '["Attention computes relationships between all positions simultaneously; RNNs process sequentially with a bottleneck state","They are equivalent","Attention is slower always","RNNs handle longer sequences better"]'::jsonb, 'Attention computes relationships between all positions simultaneously; RNNs process sequentially with a bottleneck state', 'Self-attention allows each token to attend to all others in parallel, avoiding sequential bottlenecks and enabling parallelism.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is the purpose of the key, query, and value matrices in self-attention?', '["Query-key dot products score relevance; values are weighted-summed by those scores to produce output","Keys store data; queries retrieve it; values are labels","They are three separate networks","They replace activation functions"]'::jsonb, 'Query-key dot products score relevance; values are weighted-summed by those scores to produce output', 'Q·Kᵀ/√d scores how much each token attends to others; softmax normalizes scores; result weights the values.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'What is layer normalization and how does it differ from batch normalization?', '["LayerNorm normalizes across feature dimensions per sample; BatchNorm normalizes across the batch per feature","They are identical","LayerNorm is used only in CNNs","BatchNorm requires longer sequences"]'::jsonb, 'LayerNorm normalizes across feature dimensions per sample; BatchNorm normalizes across the batch per feature', 'LayerNorm is batch-size-independent, making it preferred in RNNs and Transformers where batch statistics are unreliable.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is the dying ReLU problem and how can it be mitigated?', '["Neurons stuck at zero output due to negative pre-activations; use Leaky ReLU or ELU","Neurons that fire too often; use dropout","ReLU causing exploding gradients; use gradient clipping","No gradient for positive values; use sigmoid"]'::jsonb, 'Neurons stuck at zero output due to negative pre-activations; use Leaky ReLU or ELU', 'When a ReLU neuron always receives negative input it permanently outputs 0; Leaky ReLU allows a small negative slope.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What is depthwise separable convolution and why is it efficient?', '["It factorizes standard convolution into depthwise (per-channel) and pointwise (1×1) steps, drastically reducing parameters","It only applies convolutions to the first layer","It removes pooling layers","It is equivalent to attention"]'::jsonb, 'It factorizes standard convolution into depthwise (per-channel) and pointwise (1×1) steps, drastically reducing parameters', 'Used in MobileNet, depthwise separable convolutions reduce computation by a factor of ≈the number of channels.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is the spectral norm regularization technique in neural networks?', '["Constraining the largest singular value of weight matrices to stabilize training, especially in GANs","Adding L2 penalty to all weights","Normalizing activations per batch","Clipping weight magnitudes"]'::jsonb, 'Constraining the largest singular value of weight matrices to stabilize training, especially in GANs', 'Spectral normalization controls the Lipschitz constant of layers by dividing weights by their spectral norm.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'How does knowledge distillation work?', '["Training a small student model to mimic the soft outputs of a larger teacher model","Compressing weights numerically","Pruning neurons","Using fewer training examples"]'::jsonb, 'Training a small student model to mimic the soft outputs of a larger teacher model', 'Distillation transfers knowledge by having the student learn from the teacher''s probability distributions (soft labels).', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is neural architecture search (NAS)?', '["Automated methods for finding optimal network architectures using optimization or RL","Manually designing networks","Searching for optimal learning rates","Grid search over hyperparameters only"]'::jsonb, 'Automated methods for finding optimal network architectures using optimization or RL', 'NAS explores the architecture search space (layers, widths, connections) to discover high-performing designs automatically.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is the role of positional encoding in Transformers?', '["Injecting sequence position information since self-attention is permutation-invariant","Replacing word embeddings","Adding dropout to attention scores","Normalizing key vectors"]'::jsonb, 'Injecting sequence position information since self-attention is permutation-invariant', 'Without positional encoding, Transformers treat input as a bag of tokens; encoding adds order information.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is gradient checkpointing and what trade-off does it involve?', '["Recomputing activations during backprop to save memory at the cost of extra computation","Saving all activations to disk","Checkpointing model weights only","Limiting gradient magnitudes"]'::jsonb, 'Recomputing activations during backprop to save memory at the cost of extra computation', 'Gradient checkpointing discards intermediate activations and recomputes them during the backward pass, trading time for memory.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is the difference between model pruning and quantization for neural network compression?', '["Pruning removes low-importance weights/neurons; quantization reduces numerical precision of weights","They are the same","Pruning changes architecture; quantization changes loss function","Quantization removes layers; pruning adds layers"]'::jsonb, 'Pruning removes low-importance weights/neurons; quantization reduces numerical precision of weights', 'Pruning creates sparse networks by zeroing weights; quantization uses fewer bits (e.g., INT8) for memory and speed gains.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'How do skip connections in ResNets affect the loss landscape?', '["They smooth the loss landscape, making optimization easier and reducing saddle points","They make it more jagged","They increase the number of local minima","They have no effect on optimization"]'::jsonb, 'They smooth the loss landscape, making optimization easier and reducing saddle points', 'Skip connections create smoother, more convex loss surfaces that are easier to navigate with gradient descent.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is the InfoNCE loss used in contrastive learning?', '["A loss that maximizes agreement between augmented views of the same sample vs. negative examples","Cross-entropy for classification","Mean squared error for regression","Triplet margin loss"]'::jsonb, 'A loss that maximizes agreement between augmented views of the same sample vs. negative examples', 'InfoNCE (used in SimCLR/MoCo) trains encoders to bring positive pairs close and push negatives apart in embedding space.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is the purpose of multi-head attention in Transformers?', '["Attending to different subspaces/aspects of the input simultaneously by running attention in parallel h times","Running attention h times sequentially","Using h separate models","Replacing feedforward layers"]'::jsonb, 'Attending to different subspaces/aspects of the input simultaneously by running attention in parallel h times', 'Multi-head attention allows the model to jointly focus on information from different representation subspaces.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What is a variational autoencoder (VAE) and how does it differ from a standard autoencoder?', '["VAE encodes to a distribution (mean, variance) and samples from it, enabling generation; standard AE encodes to a point","They are identical","VAE has no decoder","Standard AE can generate new samples"]'::jsonb, 'VAE encodes to a distribution (mean, variance) and samples from it, enabling generation; standard AE encodes to a point', 'VAEs use the reparameterization trick to enable gradient flow through stochastic sampling, making generation possible.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is mixed-precision training?', '["Using FP16 for most computations and FP32 for master weights and loss scaling to speed training without precision loss","Training with random precision","Using 8-bit only","Combining different architectures"]'::jsonb, 'Using FP16 for most computations and FP32 for master weights and loss scaling to speed training without precision loss', 'Mixed precision leverages tensor cores for FP16 speed gains while maintaining FP32 precision where needed.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'How does the transformer decoder differ from the encoder in architecture?', '["Decoder adds masked self-attention and cross-attention to encoder outputs; encoder uses only self-attention","They are identical","Decoder has no attention","Encoder uses cross-attention"]'::jsonb, 'Decoder adds masked self-attention and cross-attention to encoder outputs; encoder uses only self-attention', 'The decoder masks future positions (causal attention) and attends to encoder outputs via cross-attention for generation.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What is weight tying in language models?', '["Sharing the input embedding matrix with the output projection, reducing parameters","Using identical weights in all layers","Tying learning rates across layers","Sharing weights between encoder and decoder always"]'::jsonb, 'Sharing the input embedding matrix with the output projection, reducing parameters', 'Weight tying uses the same matrix for input embeddings and the pre-softmax output projection, reducing model size.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is the computational complexity of self-attention with respect to sequence length n?', '["O(n²) in time and memory due to the attention score matrix","O(n)","O(n log n)","O(1)"]'::jsonb, 'O(n²) in time and memory due to the attention score matrix', 'Computing all pairwise Q·Kᵀ scores requires an n×n matrix, making standard attention quadratic in sequence length.', true);
END;
$$;

-- ============================================================
-- TOPIC 6: Natural Language Processing
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Natural Language Processing' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'NLP stands for Natural Language Processing. What does it help computers do?', '["Understand and work with human language","Draw pictures","Play music","Control robots"]'::jsonb, 'Understand and work with human language', 'NLP is the field of AI that helps computers read, understand, and generate human language.', true),
  (gen_random_uuid(), tid, 'story', 37, 'When a computer breaks a sentence into individual words, what is that process called?', '["Tokenization","Translation","Coloring","Sorting"]'::jsonb, 'Tokenization', 'Tokenization splits text into individual tokens (usually words or subwords) for processing.', true),
  (gen_random_uuid(), tid, 'story', 38, 'If a computer reads your email and decides if it is happy or sad, what is it doing?', '["Sentiment analysis","Drawing","Sorting","Translating"]'::jsonb, 'Sentiment analysis', 'Sentiment analysis determines the emotional tone (positive, negative, neutral) of a piece of text.', true),
  (gen_random_uuid(), tid, 'story', 39, 'What do we call it when a computer changes text from English to Spanish?', '["Machine translation","Tokenization","Summarization","Classification"]'::jsonb, 'Machine translation', 'Machine translation uses NLP models to automatically convert text from one language to another.', true),
  (gen_random_uuid(), tid, 'story', 40, 'A chatbot reads your question and writes an answer. Which AI area makes this possible?', '["Natural Language Processing","Computer Vision","Robotics","Data sorting"]'::jsonb, 'Natural Language Processing', 'NLP powers chatbots by enabling them to understand questions and generate appropriate responses.', true),
  (gen_random_uuid(), tid, 'story', 41, 'What is a vocabulary in NLP?', '["The set of all unique words the model knows","The speed of reading","The number of sentences","The size of the training data"]'::jsonb, 'The set of all unique words the model knows', 'A vocabulary is the collection of all unique tokens the NLP model recognizes and can process.', true),
  (gen_random_uuid(), tid, 'story', 42, 'When a computer reads a long article and makes a short version, what is that called?', '["Summarization","Translation","Labeling","Sorting"]'::jsonb, 'Summarization', 'Text summarization condenses a long document into a shorter version while keeping the main ideas.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What does autocomplete on your phone use to guess the next word?', '["A language model that predicts likely next words","A dictionary lookup","Random guessing","Spell check only"]'::jsonb, 'A language model that predicts likely next words', 'Language models learn word patterns and probabilities to predict the most likely next word in a sequence.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What is spell check an example of in NLP?', '["Error correction in text","Machine translation","Sentiment analysis","Image recognition"]'::jsonb, 'Error correction in text', 'Spell check detects and corrects misspelled words, a foundational NLP text-correction task.', true),
  (gen_random_uuid(), tid, 'story', 45, 'Voice assistants like Siri first turn your spoken words into text. What is that step called?', '["Speech-to-text (speech recognition)","Translation","Summarization","Sentiment analysis"]'::jsonb, 'Speech-to-text (speech recognition)', 'Speech recognition converts spoken audio into written text, which NLP then processes for understanding.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What is the meaning of a word based on the words around it called?', '["Context","Grammar","Spelling","Punctuation"]'::jsonb, 'Context', 'Context refers to the surrounding words that help determine the meaning of an ambiguous word.', true),
  (gen_random_uuid(), tid, 'story', 47, 'A computer finds all the names of people in a news article. What task is that?', '["Named entity recognition","Summarization","Translation","Sentiment analysis"]'::jsonb, 'Named entity recognition', 'Named entity recognition (NER) identifies and classifies named entities like people, places, and organizations in text.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What makes human language hard for computers to understand?', '["Words can mean different things depending on context","Letters are hard to read","Sentences are always long","Computers cannot see letters"]'::jsonb, 'Words can mean different things depending on context', 'Ambiguity and context-dependence in natural language make it much harder to process than formal programming languages.', true),
  (gen_random_uuid(), tid, 'story', 49, 'What do we call removing common words like "the" and "is" that do not add much meaning?', '["Stop word removal","Tokenization","Summarization","Labeling"]'::jsonb, 'Stop word removal', 'Stop words (the, a, is) are often removed before NLP processing to focus on meaningful content words.', true),
  (gen_random_uuid(), tid, 'story', 50, 'What is question answering in NLP?', '["A system that reads a text and answers questions about it","A spelling checker","A translation tool","A summarizer"]'::jsonb, 'A system that reads a text and answers questions about it', 'Question answering systems extract or generate answers to questions based on a given passage of text.', true),
  (gen_random_uuid(), tid, 'story', 51, 'Which of these is an example of NLP in everyday life?', '["Email spam filter","Traffic light","Calculator","Thermometer"]'::jsonb, 'Email spam filter', 'Spam filters use NLP to analyze email text and classify messages as spam or legitimate.', true),
  (gen_random_uuid(), tid, 'story', 52, 'A computer reads a review and decides if the customer liked the product. What is it doing?', '["Sentiment analysis","Named entity recognition","Tokenization","Translation"]'::jsonb, 'Sentiment analysis', 'Sentiment analysis classifies the emotional opinion in text, like determining if a review is positive or negative.', true),
  (gen_random_uuid(), tid, 'story', 53, 'What does it mean when a language model "generates" text?', '["It creates new words and sentences based on patterns it learned","It copies text from a book","It translates text","It counts words"]'::jsonb, 'It creates new words and sentences based on patterns it learned', 'Text generation uses learned language patterns to produce new, coherent sentences or paragraphs.', true),
  (gen_random_uuid(), tid, 'story', 54, 'What is a corpus in NLP?', '["A large collection of text used to train language models","A single sentence","A type of neural network","A list of labels"]'::jsonb, 'A large collection of text used to train language models', 'A corpus is a large dataset of text (books, articles, web pages) used to train NLP models.', true),
  (gen_random_uuid(), tid, 'story', 55, 'When a phone turns your voice into words, and then an app answers your question, which two technologies work together?', '["Speech recognition and NLP","Computer vision and robotics","Math and spelling","Drawing and sorting"]'::jsonb, 'Speech recognition and NLP', 'Voice assistants combine speech recognition (audio to text) with NLP (understanding and responding to text).', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What is a word embedding?', '["A dense vector representation of a word that captures semantic meaning","A word translated to another language","A type of tokenization","A grammar rule"]'::jsonb, 'A dense vector representation of a word that captures semantic meaning', 'Word embeddings map words to numerical vectors where semantically similar words are close in vector space.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What does Word2Vec capture in its word vectors?', '["Semantic and syntactic relationships — similar words have similar vectors","Only spelling patterns","Only frequency counts","Only grammar rules"]'::jsonb, 'Semantic and syntactic relationships — similar words have similar vectors', 'Word2Vec trains on context windows and captures analogies like king - man + woman = queen.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What is the bag-of-words model?', '["Representing text as word frequency counts, ignoring order","A type of recurrent network","A method for machine translation","A clustering algorithm"]'::jsonb, 'Representing text as word frequency counts, ignoring order', 'Bag-of-words creates a vocabulary-sized vector of word counts, discarding all positional information.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What does TF-IDF measure?', '["How important a word is to a document relative to a corpus — common words get lower weight","Word frequency only","Sentence length","Grammar complexity"]'::jsonb, 'How important a word is to a document relative to a corpus — common words get lower weight', 'TF-IDF boosts rare, informative words and penalizes common words that appear in many documents.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is stemming in NLP?', '["Reducing words to their root form (e.g., running → run)","Translating words","Adding prefixes","Counting syllables"]'::jsonb, 'Reducing words to their root form (e.g., running → run)', 'Stemming strips word suffixes to normalize forms, though it may produce non-dictionary roots.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'How does lemmatization differ from stemming?', '["Lemmatization returns the dictionary base form; stemming may produce non-words","They are identical","Stemming is more accurate","Lemmatization only works in English"]'::jsonb, 'Lemmatization returns the dictionary base form; stemming may produce non-words', 'Lemmatization uses linguistic knowledge to return the proper dictionary form (lemma), not just a clipped stem.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What is part-of-speech tagging?', '["Labeling each word with its grammatical role (noun, verb, adjective, etc.)","Counting words","Translating text","Removing stop words"]'::jsonb, 'Labeling each word with its grammatical role (noun, verb, adjective, etc.)', 'POS tagging assigns grammatical categories to tokens, which is foundational for parsing and information extraction.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What is coreference resolution?', '["Identifying when different words or phrases refer to the same entity (e.g., ''John said he was tired'')","Translating pronouns","Counting entity mentions","Removing duplicates"]'::jsonb, 'Identifying when different words or phrases refer to the same entity (e.g., ''John said he was tired'')', 'Coreference resolution links pronouns and noun phrases to the entities they refer to in a text.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is a language model''s perplexity?', '["A measure of how well a model predicts a sample — lower is better","The number of parameters","How confused the model looks","Training accuracy"]'::jsonb, 'A measure of how well a model predicts a sample — lower is better', 'Perplexity is the exponentiated average negative log-likelihood; a lower value means the model assigns higher probability to the text.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is the encoder-decoder architecture used for in NLP?', '["Sequence-to-sequence tasks like translation — encoder processes input, decoder generates output","Only text classification","Only tokenization","Named entity recognition only"]'::jsonb, 'Sequence-to-sequence tasks like translation — encoder processes input, decoder generates output', 'Seq2seq models encode the source sequence into a context vector, then decode it to the target sequence.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What is BERT and how is it trained?', '["A Transformer encoder pre-trained on masked language modeling and next sentence prediction","A decoder-only model","A rule-based parser","A word2vec model"]'::jsonb, 'A Transformer encoder pre-trained on masked language modeling and next sentence prediction', 'BERT masks random tokens and trains the model to predict them, learning deep bidirectional representations.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is the attention mechanism''s role in NLP?', '["Allowing the model to focus on relevant parts of the input when generating each output token","Removing stop words","Counting word frequencies","Performing tokenization"]'::jsonb, 'Allowing the model to focus on relevant parts of the input when generating each output token', 'Attention weights allow the model to selectively emphasize relevant input positions for each output step.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is subword tokenization and why is it used?', '["Breaking rare words into smaller units to handle out-of-vocabulary words","Removing subwords","Counting syllables","Translating morphemes"]'::jsonb, 'Breaking rare words into smaller units to handle out-of-vocabulary words', 'Subword methods (BPE, WordPiece) balance vocabulary size and OOV handling by splitting rare words into common pieces.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What does GPT stand for and what is its training objective?', '["Generative Pre-trained Transformer; trained to predict the next token","General Purpose Text; trained on sentiment","Global Pattern Tokenizer; trained on translations","Graph Processing Tool; trained on code"]'::jsonb, 'Generative Pre-trained Transformer; trained to predict the next token', 'GPT uses a causal (left-to-right) language modeling objective, predicting each token from all previous tokens.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is zero-shot learning in NLP?', '["A model performs a task it was never explicitly trained on by using natural language instructions","Training on zero examples","A type of tokenization","Removing all labels"]'::jsonb, 'A model performs a task it was never explicitly trained on by using natural language instructions', 'Zero-shot NLP leverages a model''s general knowledge to follow task descriptions without task-specific training examples.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is dependency parsing?', '["Analyzing grammatical relationships between words in a sentence","Counting dependencies in code","Removing stop words","Translating syntax trees"]'::jsonb, 'Analyzing grammatical relationships between words in a sentence', 'Dependency parsing builds a tree showing how words relate grammatically (subject-verb, modifier-noun, etc.).', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is text classification used for?', '["Assigning predefined categories to text (spam detection, topic labeling, sentiment)","Only translating text","Generating text","Parsing sentences"]'::jsonb, 'Assigning predefined categories to text (spam detection, topic labeling, sentiment)', 'Text classification maps documents to categories and is one of the most common NLP tasks.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What is the BLEU score used to evaluate?', '["Machine translation quality by comparing to human reference translations","Summarization accuracy","Sentiment model performance","NER precision"]'::jsonb, 'Machine translation quality by comparing to human reference translations', 'BLEU measures n-gram overlap between generated translations and human references, with a brevity penalty.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is prompt engineering?', '["Crafting input text to guide a language model toward desired outputs","Training a new model","Adding more layers","Changing tokenization"]'::jsonb, 'Crafting input text to guide a language model toward desired outputs', 'Prompt engineering designs input prompts to elicit specific, high-quality responses from pre-trained language models.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What is topic modeling?', '["Discovering abstract topics in a collection of documents (e.g., LDA)","Labeling words by grammar","Translating documents","Sentiment classification"]'::jsonb, 'Discovering abstract topics in a collection of documents (e.g., LDA)', 'Topic modeling uncovers latent themes in a corpus by finding groups of co-occurring words.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is byte-pair encoding (BPE) and how does it build a vocabulary?', '["Iteratively merging the most frequent adjacent symbol pairs until a vocabulary size is reached","Encoding bytes directly","Splitting text on spaces only","A character-level model"]'::jsonb, 'Iteratively merging the most frequent adjacent symbol pairs until a vocabulary size is reached', 'BPE starts with characters and greedily merges frequent pairs, producing a vocabulary of variable-length subword units.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'How does masked language modeling (MLM) in BERT differ from causal language modeling (CLM) in GPT?', '["MLM masks tokens and predicts them from both directions; CLM predicts left-to-right only","They are identical","MLM is decoder-only; CLM uses an encoder","CLM masks random tokens"]'::jsonb, 'MLM masks tokens and predicts them from both directions; CLM predicts left-to-right only', 'MLM enables bidirectional context for understanding; CLM''s autoregressive nature suits text generation.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is the ROUGE metric and when is it used?', '["Recall-Oriented Understudy for Gisting Evaluation — measures overlap for summarization and translation","A precision metric for NER","An accuracy metric for classification","A perplexity variant"]'::jsonb, 'Recall-Oriented Understudy for Gisting Evaluation — measures overlap for summarization and translation', 'ROUGE computes n-gram recall between generated summaries and human references, complementing BLEU''s precision focus.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'What is retrieval-augmented generation (RAG)?', '["Combining a retriever that fetches relevant documents with a generator that conditions on them","Pre-training on retrieved data only","A type of attention mechanism","Training without a corpus"]'::jsonb, 'Combining a retriever that fetches relevant documents with a generator that conditions on them', 'RAG reduces hallucinations by grounding generation in retrieved factual documents from an external knowledge base.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is instruction tuning (RLHF-adjacent) and why does it improve LLM usability?', '["Fine-tuning a pre-trained LLM on instruction-response pairs so it better follows user directions","Training from scratch on instructions","A type of tokenization","Changing the model architecture"]'::jsonb, 'Fine-tuning a pre-trained LLM on instruction-response pairs so it better follows user directions', 'Instruction tuning aligns LLM outputs with human intent by training on diverse task instructions and expected responses.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What problem does hallucination refer to in large language models?', '["Generating confident, fluent text that is factually incorrect","Repeating the prompt verbatim","Refusing all requests","Producing very short outputs"]'::jsonb, 'Generating confident, fluent text that is factually incorrect', 'LLMs can produce plausible-sounding but false information because they optimize fluency, not factual accuracy.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is constitutional AI (CAI) in the context of LLM alignment?', '["Training models to critique and revise their outputs based on a set of principles","A hardware architecture","A tokenization scheme","A type of attention"]'::jsonb, 'Training models to critique and revise their outputs based on a set of principles', 'CAI uses a set of rules (constitution) to self-critique and refine responses, reducing the need for human feedback labels.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What is the difference between extractive and abstractive summarization?', '["Extractive selects verbatim sentences; abstractive generates new sentences capturing the meaning","They are identical","Extractive always produces shorter summaries","Abstractive only works in English"]'::jsonb, 'Extractive selects verbatim sentences; abstractive generates new sentences capturing the meaning', 'Extractive summarization picks existing sentences; abstractive models paraphrase and synthesize new text.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is semantic textual similarity (STS) and how is it evaluated?', '["Measuring how similar the meaning of two texts is, scored against human judgments using Pearson/Spearman correlation","Counting shared words","Checking grammar","Measuring translation accuracy"]'::jsonb, 'Measuring how similar the meaning of two texts is, scored against human judgments using Pearson/Spearman correlation', 'STS benchmarks correlate model similarity scores with human ratings, testing how well models capture meaning.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is the purpose of the [CLS] token in BERT?', '["Aggregating sequence-level representation for classification tasks","Marking the beginning of every sentence always","A stop word token","Separating two sentences"]'::jsonb, 'Aggregating sequence-level representation for classification tasks', 'BERT''s [CLS] token representation at the final layer is used as the sentence embedding for classification.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is parameter-efficient fine-tuning (PEFT) and give an example?', '["Fine-tuning a small number of parameters rather than the full model — e.g., LoRA adds low-rank adapters","Training from scratch","Pruning the model","Using fewer training examples only"]'::jsonb, 'Fine-tuning a small number of parameters rather than the full model — e.g., LoRA adds low-rank adapters', 'PEFT methods like LoRA, prefix tuning, and adapters dramatically reduce training costs while matching full fine-tuning quality.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is cross-lingual transfer in NLP?', '["A model trained on one language performing tasks in another language it was not explicitly trained on","Word-for-word translation","Using English data only","A type of tokenization"]'::jsonb, 'A model trained on one language performing tasks in another language it was not explicitly trained on', 'Multilingual models like mBERT and XLM-R develop shared representations enabling zero-shot cross-lingual transfer.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is a decoder-only transformer used for versus an encoder-only transformer?', '["Decoder-only (GPT) is used for generation; encoder-only (BERT) is used for understanding/classification","They are identical","Encoder-only generates text; decoder-only classifies","Decoder-only cannot handle text"]'::jsonb, 'Decoder-only (GPT) is used for generation; encoder-only (BERT) is used for understanding/classification', 'Causal decoder-only models excel at generation; bidirectional encoder-only models excel at representation for downstream tasks.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'How does chain-of-thought (CoT) prompting improve reasoning in LLMs?', '["Prompting the model to show intermediate reasoning steps, improving accuracy on complex tasks","Making the model faster","Reducing token usage","Replacing fine-tuning"]'::jsonb, 'Prompting the model to show intermediate reasoning steps, improving accuracy on complex tasks', 'CoT prompting encourages step-by-step reasoning, significantly improving performance on math, logic, and multi-step problems.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is a sentence transformer (bi-encoder) and how does it differ from a cross-encoder?', '["Bi-encoder independently encodes two sentences to compare embeddings; cross-encoder concatenates them for deeper interaction","They are identical","Cross-encoders are faster at retrieval","Bi-encoders require fine-tuning always"]'::jsonb, 'Bi-encoder independently encodes two sentences to compare embeddings; cross-encoder concatenates them for deeper interaction', 'Bi-encoders enable fast retrieval via pre-computed embeddings; cross-encoders are slower but more accurate for reranking.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What is the GLUE benchmark?', '["A suite of NLP tasks (sentiment, NLI, QA) used to evaluate general language understanding","A single classification dataset","A machine translation metric","A tokenization standard"]'::jsonb, 'A suite of NLP tasks (sentiment, NLI, QA) used to evaluate general language understanding', 'GLUE aggregates diverse NLP tasks to benchmark models'' general language understanding capabilities.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is natural language inference (NLI)?', '["Determining whether a hypothesis is entailed, contradicted, or neutral with respect to a premise","Translating natural language to SQL","Parsing sentences","Summarizing documents"]'::jsonb, 'Determining whether a hypothesis is entailed, contradicted, or neutral with respect to a premise', 'NLI (textual entailment) classifies the logical relationship between a premise and hypothesis as entail/contradict/neutral.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'How does positional encoding differ between learned and sinusoidal approaches?', '["Sinusoidal uses fixed trigonometric functions; learned embeddings are trained with the model and may generalize less to longer sequences","They are identical","Learned is always better","Sinusoidal cannot encode long sequences"]'::jsonb, 'Sinusoidal uses fixed trigonometric functions; learned embeddings are trained with the model and may generalize less to longer sequences', 'Sinusoidal encoding generalizes to unseen lengths; learned embeddings adapt to training data but may not extrapolate.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What is the temperature parameter in language model text generation?', '["Scales logits before softmax — higher temperature produces more diverse outputs; lower produces more focused ones","The physical temperature of the GPU","A learning rate parameter","The number of output tokens"]'::jsonb, 'Scales logits before softmax — higher temperature produces more diverse outputs; lower produces more focused ones', 'Temperature T divides logits before softmax: T→0 approaches argmax, T=1 is standard, T>1 flattens the distribution.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is token-level versus sequence-level labeling in NLP, and give an example of each?', '["Token-level labels each token (e.g., NER, POS tagging); sequence-level labels the whole input (e.g., sentiment classification)","They are the same","Token-level is only for translation","Sequence-level labels individual tokens"]'::jsonb, 'Token-level labels each token (e.g., NER, POS tagging); sequence-level labels the whole input (e.g., sentiment classification)', 'Token-level tasks produce per-token outputs; sequence-level tasks produce one label for the entire input text.', true);
END;
$$;

-- ============================================================
-- TOPIC 7: Computer Vision
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Computer Vision' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'Computer vision helps machines do what?', '["See and understand pictures and videos","Listen to music","Read books","Do math"]'::jsonb, 'See and understand pictures and videos', 'Computer vision is the field of AI that enables machines to interpret and understand visual information.', true),
  (gen_random_uuid(), tid, 'story', 37, 'A digital image is made up of tiny squares of color called what?', '["Pixels","Bytes","Dots only","Shapes"]'::jsonb, 'Pixels', 'Images are grids of pixels, each with a color value. Computer vision algorithms analyze these pixel values.', true),
  (gen_random_uuid(), tid, 'story', 38, 'When a computer looks at a photo and says "that is a cat," what task is it doing?', '["Image classification","Image drawing","Image deleting","Image compressing"]'::jsonb, 'Image classification', 'Image classification assigns a label to an entire image, like identifying it contains a cat.', true),
  (gen_random_uuid(), tid, 'story', 39, 'When a computer draws a box around the cat in a photo, what task is that?', '["Object detection","Image classification","Image coloring","Image sorting"]'::jsonb, 'Object detection', 'Object detection locates and identifies objects in an image, drawing bounding boxes around them.', true),
  (gen_random_uuid(), tid, 'story', 40, 'Which tool in a phone uses computer vision to let you try on virtual sunglasses?', '["Augmented reality filter","Calculator","Alarm clock","Compass"]'::jsonb, 'Augmented reality filter', 'AR filters use computer vision to detect your face and overlay virtual objects on it in real time.', true),
  (gen_random_uuid(), tid, 'story', 41, 'Computers represent colors using how many color channels in a standard color image?', '["3 (red, green, blue)","1","4","2"]'::jsonb, '3 (red, green, blue)', 'Standard color images use three channels — red, green, and blue — to represent every color.', true),
  (gen_random_uuid(), tid, 'story', 42, 'What do we call an image that is only black and white with no colors?', '["Grayscale image","Pixel image","Color map","Binary photo"]'::jsonb, 'Grayscale image', 'A grayscale image has one channel with pixel values from 0 (black) to 255 (white).', true),
  (gen_random_uuid(), tid, 'story', 43, 'Face recognition on a phone uses computer vision to do what?', '["Identify your face to unlock the phone","Play music","Take photos","Set the alarm"]'::jsonb, 'Identify your face to unlock the phone', 'Face recognition matches detected facial features to stored patterns to verify identity.', true),
  (gen_random_uuid(), tid, 'story', 44, 'Self-driving cars use computer vision for which task?', '["Detecting road signs, pedestrians, and other vehicles","Playing music in the car","Tracking fuel","Choosing a radio station"]'::jsonb, 'Detecting road signs, pedestrians, and other vehicles', 'Autonomous vehicles use real-time computer vision to understand their surroundings and navigate safely.', true),
  (gen_random_uuid(), tid, 'story', 45, 'What is the first step when teaching a computer to recognize photos of dogs?', '["Giving it many labeled photos of dogs and non-dogs","Showing it one photo","Telling it the word dog","Drawing a dog"]'::jsonb, 'Giving it many labeled photos of dogs and non-dogs', 'Supervised learning for image classification requires many labeled training examples for each category.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What does a camera capture that a computer vision system then analyzes?', '["Light reflected from objects as an image","Sound waves","Temperature data","GPS location"]'::jsonb, 'Light reflected from objects as an image', 'Cameras capture reflected light and convert it to pixel grids that computer vision algorithms process.', true),
  (gen_random_uuid(), tid, 'story', 47, 'When a doctor uses AI to look at X-rays and spot problems, what is the AI using?', '["Computer vision","NLP","Robotics","Sorting algorithms"]'::jsonb, 'Computer vision', 'Medical imaging AI applies computer vision to analyze X-rays, MRIs, and scans for diagnostic patterns.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What is image segmentation?', '["Dividing an image into regions or objects, like coloring each object a different color","Making images smaller","Turning images black and white","Sorting images by date"]'::jsonb, 'Dividing an image into regions or objects, like coloring each object a different color', 'Image segmentation assigns a label to every pixel, distinguishing between different objects or regions.', true),
  (gen_random_uuid(), tid, 'story', 49, 'A barcode scanner at a store uses computer vision to do what?', '["Read the pattern of lines to find the product code","Play a sound","Weigh the item","Print a receipt"]'::jsonb, 'Read the pattern of lines to find the product code', 'Barcode scanners use optical recognition to decode the pattern of bars into a product identifier.', true),
  (gen_random_uuid(), tid, 'story', 50, 'What does "resolution" mean for an image?', '["The number of pixels — more pixels means more detail","The color of the image","The brightness","The file size only"]'::jsonb, 'The number of pixels — more pixels means more detail', 'Higher resolution means more pixels, providing finer detail and larger file sizes.', true),
  (gen_random_uuid(), tid, 'story', 51, 'What special kind of neural network is best at analyzing images?', '["Convolutional Neural Network (CNN)","Recurrent Neural Network","Decision tree","K-means"]'::jsonb, 'Convolutional Neural Network (CNN)', 'CNNs are designed for grid-like data (images) and automatically learn spatial feature detectors.', true),
  (gen_random_uuid(), tid, 'story', 52, 'What is optical character recognition (OCR)?', '["Converting images of printed text into editable digital text","Drawing characters","Sorting fonts","Counting letters"]'::jsonb, 'Converting images of printed text into editable digital text', 'OCR reads text from photos or scanned documents and converts it to machine-readable characters.', true),
  (gen_random_uuid(), tid, 'story', 53, 'How does a game that reacts to your body movements use computer vision?', '["It detects your pose and position from a camera feed","It uses a special controller","It reads your thoughts","It counts your steps"]'::jsonb, 'It detects your pose and position from a camera feed', 'Pose estimation uses computer vision to detect body joint positions and track movements in real time.', true),
  (gen_random_uuid(), tid, 'story', 54, 'What does data augmentation in image training mean?', '["Creating variations of training images (flipping, rotating) to help the model learn better","Deleting images","Adding more cameras","Printing images"]'::jsonb, 'Creating variations of training images (flipping, rotating) to help the model learn better', 'Data augmentation artificially expands training data by applying transformations, improving model robustness.', true),
  (gen_random_uuid(), tid, 'story', 55, 'What is the difference between a photo and a video in computer vision terms?', '["A video is a sequence of images (frames) over time","A video is just one big image","Photos have more pixels","Videos are black and white"]'::jsonb, 'A video is a sequence of images (frames) over time', 'Videos are streams of images (frames); computer vision can analyze individual frames or temporal patterns across frames.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What is a convolutional filter and what does sliding it over an image produce?', '["A small matrix of learnable weights that produces a feature map highlighting certain patterns","A type of pooling","A fully connected layer","An image classifier"]'::jsonb, 'A small matrix of learnable weights that produces a feature map highlighting certain patterns', 'Convolution applies a filter element-wise across the input, creating an activation map showing where patterns appear.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What is max pooling and why is it used?', '["Taking the maximum value in each window to downsample while retaining dominant features","Averaging all pixel values","Adding noise","Increasing resolution"]'::jsonb, 'Taking the maximum value in each window to downsample while retaining dominant features', 'Max pooling reduces spatial dimensions and introduces translation invariance by retaining the strongest activations.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What is image normalization in preprocessing?', '["Scaling pixel values to a standard range (e.g., 0-1 or zero mean/unit variance) for stable training","Resizing images","Converting to grayscale","Applying edge detection"]'::jsonb, 'Scaling pixel values to a standard range (e.g., 0-1 or zero mean/unit variance) for stable training', 'Normalizing pixel values prevents large inputs from dominating gradients and speeds up neural network convergence.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What does the stride parameter in a convolution control?', '["How many pixels the filter moves at each step, affecting output size","The filter size","The number of filters","The padding amount"]'::jsonb, 'How many pixels the filter moves at each step, affecting output size', 'A stride of 1 moves one pixel at a time; larger strides reduce output dimensions more aggressively.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is transfer learning in computer vision?', '["Using a CNN pre-trained on ImageNet as a feature extractor or starting point for a new vision task","Training from random weights","Using only the output layer","Data augmentation"]'::jsonb, 'Using a CNN pre-trained on ImageNet as a feature extractor or starting point for a new vision task', 'Pre-trained CNNs capture general visual features that transfer well to new tasks with far less training data.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What is the difference between semantic segmentation and instance segmentation?', '["Semantic assigns a class to every pixel; instance also distinguishes individual objects of the same class","They are identical","Instance only detects two classes","Semantic draws bounding boxes"]'::jsonb, 'Semantic assigns a class to every pixel; instance also distinguishes individual objects of the same class', 'Semantic segmentation labels pixels by class; instance segmentation separately identifies each object instance.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What is an anchor box in object detection?', '["A predefined bounding box shape/scale the model adjusts to detect objects","A type of pooling","A convolutional filter","A loss function"]'::jsonb, 'A predefined bounding box shape/scale the model adjusts to detect objects', 'Anchor boxes define prior box shapes; the model learns offsets to fit them to actual objects.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What does IoU (Intersection over Union) measure in object detection?', '["The overlap between predicted and ground truth bounding boxes","Image resolution","Color similarity","Feature map size"]'::jsonb, 'The overlap between predicted and ground truth bounding boxes', 'IoU = intersection area / union area; higher IoU means the predicted box better matches the ground truth.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is non-maximum suppression (NMS)?', '["Removing duplicate overlapping detections by keeping only the most confident box","A pooling technique","An activation function","A regularization method"]'::jsonb, 'Removing duplicate overlapping detections by keeping only the most confident box', 'NMS suppresses redundant bounding boxes by discarding lower-confidence boxes with high IoU overlap.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is the purpose of padding in convolutions?', '["Preserving spatial dimensions and border information by adding zeros around the input","Increasing filter size","Adding noise","Normalizing features"]'::jsonb, 'Preserving spatial dimensions and border information by adding zeros around the input', 'Padding (typically zero-padding) prevents spatial shrinkage with each convolution and lets edge pixels contribute equally.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'Which architecture introduced batch normalization and very deep (19-layer) networks, winning ImageNet 2014?', '["VGGNet","AlexNet","ResNet","GoogLeNet"]'::jsonb, 'VGGNet', 'VGGNet used only 3×3 filters stacked deeply with batch normalization, demonstrating depth''s importance.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is a depth-wise separable convolution (used in MobileNet)?', '["Applying a single filter per input channel, then mixing channels with 1×1 convolutions","Standard convolution with large filters","A pooling method","Attention over spatial dimensions"]'::jsonb, 'Applying a single filter per input channel, then mixing channels with 1×1 convolutions', 'Depth-wise separable convolutions achieve similar accuracy to standard convolutions with far fewer parameters.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is the purpose of the Softmax layer at the end of an image classifier CNN?', '["Converting raw class scores to probabilities summing to 1","Detecting edges","Performing pooling","Normalizing feature maps"]'::jsonb, 'Converting raw class scores to probabilities summing to 1', 'Softmax turns the final logits into a probability distribution over all classes for classification.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What is an image embedding?', '["A compact vector representation of an image capturing its visual content","A larger version of the image","A bounding box","The image''s pixel grid flattened"]'::jsonb, 'A compact vector representation of an image capturing its visual content', 'Image embeddings encode visual features in a dense vector where similar images are close in embedding space.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is the role of activation functions after convolutional layers?', '["Introducing non-linearity so the network can learn complex patterns","Normalizing outputs","Pooling feature maps","Computing the loss"]'::jsonb, 'Introducing non-linearity so the network can learn complex patterns', 'Without activation functions, stacking conv layers would still produce linear operations — ReLU adds essential non-linearity.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'How does YOLO (You Only Look Once) differ from two-stage detectors like Faster R-CNN?', '["YOLO predicts boxes and classes in one pass; Faster R-CNN first proposes regions then classifies them","YOLO is always more accurate","Faster R-CNN runs in real time","They use identical architectures"]'::jsonb, 'YOLO predicts boxes and classes in one pass; Faster R-CNN first proposes regions then classifies them', 'YOLO''s single-pass design enables real-time detection; two-stage methods trade speed for higher accuracy.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is the vanishing gradient challenge specific to very deep CNNs and how did ResNets solve it?', '["Deep layers receive near-zero gradients; ResNets add skip connections so gradients can flow directly","Pooling removes gradients; ResNets remove pooling","Stride 1 prevents gradients; stride 2 fixes it","Batch size causes it; larger batches fix it"]'::jsonb, 'Deep layers receive near-zero gradients; ResNets add skip connections so gradients can flow directly', 'ResNet''s identity shortcuts create direct gradient paths, enabling training of 100+ layer networks.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What does the receptive field of a CNN layer represent?', '["The area of the original image that influences a given neuron''s activation","The number of filters","The pooling window","The stride"]'::jsonb, 'The area of the original image that influences a given neuron''s activation', 'Deeper layers have larger receptive fields, allowing them to detect global structures rather than local edges.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is knowledge distillation in computer vision?', '["Training a compact student CNN to match a larger teacher model''s outputs, preserving accuracy with fewer parameters","Training with fewer images","Compressing image files","Reducing filter size"]'::jsonb, 'Training a compact student CNN to match a larger teacher model''s outputs, preserving accuracy with fewer parameters', 'Distillation transfers the teacher''s learned dark knowledge (soft probabilities) to a smaller, faster student model.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What is optical flow in video analysis?', '["Estimating the motion of pixels between consecutive frames","Detecting colors in video","Segmenting audio","Classifying video genres"]'::jsonb, 'Estimating the motion of pixels between consecutive frames', 'Optical flow computes per-pixel velocity vectors showing how image content moves across frames in a video.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'How does the Vision Transformer (ViT) process images differently from CNNs?', '["ViT splits images into fixed-size patches, embeds them, and applies Transformer self-attention; CNNs use local convolutional filters","ViT uses convolutions at every layer","CNNs use patches","ViT cannot process color images"]'::jsonb, 'ViT splits images into fixed-size patches, embeds them, and applies Transformer self-attention; CNNs use local convolutional filters', 'ViT treats image patches as tokens, enabling global attention from the first layer unlike CNN''s local inductive bias.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'What is contrastive learning in computer vision (e.g., SimCLR)?', '["Training an encoder to produce similar representations for augmented views of the same image and dissimilar for different images","Supervised image classification","Detecting objects with bounding boxes","A type of pooling"]'::jsonb, 'Training an encoder to produce similar representations for augmented views of the same image and dissimilar for different images', 'Self-supervised contrastive methods learn visual representations without labels, matching views of the same sample.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is the role of the Region Proposal Network (RPN) in Faster R-CNN?', '["Generating candidate bounding box proposals with objectness scores for the detection head","Classifying every pixel","Performing non-maximum suppression","Computing anchor offsets"]'::jsonb, 'Generating candidate bounding box proposals with objectness scores for the detection head', 'The RPN slides over feature maps to propose potential object locations, which are then classified and refined.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'What is neural style transfer and what two losses does it minimize?', '["Transferring artistic style onto a content image; minimizing content loss (feature maps) and style loss (Gram matrices)","Classifying painting styles","Segmenting artwork","Detecting objects in paintings"]'::jsonb, 'Transferring artistic style onto a content image; minimizing content loss (feature maps) and style loss (Gram matrices)', 'NST optimizes a target image to match one image''s content features and another''s style correlations (Gram matrices).', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'How does masked image modeling (e.g., MAE) enable self-supervised visual learning?', '["Masking random image patches and training the model to reconstruct them, learning rich representations","Labeling every patch","Using contrastive loss only","Applying dropout to images"]'::jsonb, 'Masking random image patches and training the model to reconstruct them, learning rich representations', 'Masked Autoencoders mask 75%+ of patches and reconstruct pixel values, learning semantically rich features.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What is the FPN (Feature Pyramid Network) and why is it used in object detection?', '["A multi-scale feature hierarchy that enables detection of objects at different sizes","A type of attention","A loss function","A data augmentation technique"]'::jsonb, 'A multi-scale feature hierarchy that enables detection of objects at different sizes', 'FPN combines low-resolution deep features with high-resolution shallow ones via top-down pathway and lateral connections.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is deformable convolution and what advantage does it have?', '["Offsets the sampling grid dynamically, allowing the network to focus on irregularly shaped objects","Applies convolutions at higher resolution","Uses separable filters","Reduces computation by 2x"]'::jsonb, 'Offsets the sampling grid dynamically, allowing the network to focus on irregularly shaped objects', 'Deformable convolutions learn spatial offsets per feature, enabling adaptive receptive fields for geometric transformations.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What does mean Average Precision (mAP) measure in object detection?', '["Average precision across IoU thresholds and across all object classes","Pixel accuracy","Model speed","Bounding box area"]'::jsonb, 'Average precision across IoU thresholds and across all object classes', 'mAP integrates the precision-recall curve across detection thresholds and averages over all categories.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is the panoptic segmentation task?', '["Combining semantic segmentation (all pixels labeled) and instance segmentation (individual objects differentiated)","Only detecting bounding boxes","Classifying entire images","Tracking objects over time"]'::jsonb, 'Combining semantic segmentation (all pixels labeled) and instance segmentation (individual objects differentiated)', 'Panoptic segmentation unifies stuff (background regions) and things (countable objects) into a single cohesive scene understanding.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'How does the DINO self-supervised method differ from contrastive approaches?', '["DINO uses self-distillation with a momentum teacher and no negative pairs; contrastive methods require negatives","They are identical","DINO uses labels","DINO applies only to text"]'::jsonb, 'DINO uses self-distillation with a momentum teacher and no negative pairs; contrastive methods require negatives', 'DINO matches student outputs to a momentum-averaged teacher without requiring explicit negative examples.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is test-time augmentation (TTA) and how does it improve predictions?', '["Applying multiple augmentations at inference and averaging predictions to reduce variance","A training technique","A type of regularization","Data preprocessing only"]'::jsonb, 'Applying multiple augmentations at inference and averaging predictions to reduce variance', 'TTA creates multiple augmented copies of the test image, averages their predictions, improving robustness and accuracy.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is CLIP and how does it connect computer vision and NLP?', '["CLIP trains image and text encoders jointly on image-text pairs with contrastive loss, enabling zero-shot image classification","A type of CNN only","An object detection model","A style transfer method"]'::jsonb, 'CLIP trains image and text encoders jointly on image-text pairs with contrastive loss, enabling zero-shot image classification', 'CLIP aligns image and text embeddings, allowing classification via text prompts without task-specific fine-tuning.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is the Grad-CAM technique used for?', '["Visualizing which regions of an image influenced a CNN''s classification decision by using gradient-weighted activation maps","Training CNNs faster","A type of data augmentation","Compressing models"]'::jsonb, 'Visualizing which regions of an image influenced a CNN''s classification decision by using gradient-weighted activation maps', 'Grad-CAM uses gradients of the target class flowing into the last convolutional layer to produce a saliency heatmap.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is a diffusion model in image generation?', '["A model that learns to denoise images, trained by adding noise and learning to reverse the process","A type of GAN","A classification model","A segmentation model"]'::jsonb, 'A model that learns to denoise images, trained by adding noise and learning to reverse the process', 'Diffusion models (e.g., DDPM, Stable Diffusion) iteratively denoise random noise into high-quality images.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is the difference between one-stage and two-stage object detectors in terms of speed/accuracy tradeoff?', '["One-stage (YOLO, SSD) is faster but less accurate; two-stage (Faster R-CNN) is slower but more accurate","One-stage is always more accurate","Two-stage always runs faster","They perform identically"]'::jsonb, 'One-stage (YOLO, SSD) is faster but less accurate; two-stage (Faster R-CNN) is slower but more accurate', 'One-stage detectors skip region proposal for speed; two-stage methods''s proposal+classification pipeline yields better accuracy.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What is few-shot learning in computer vision?', '["Generalizing to new classes with only 1-5 examples per class, using meta-learning or embedding similarity","Training on large datasets","A type of data augmentation","Transfer learning only"]'::jsonb, 'Generalizing to new classes with only 1-5 examples per class, using meta-learning or embedding similarity', 'Few-shot learning methods like prototypical networks learn to compare embeddings to classify from very few examples.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is 3D object detection and what sensors enable it beyond RGB cameras?', '["Detecting objects in 3D space; LiDAR point clouds and depth cameras provide 3D structure","2D detection with more channels","Only RGB cameras at different angles","Infrared cameras only"]'::jsonb, 'Detecting objects in 3D space; LiDAR point clouds and depth cameras provide 3D structure', 'Autonomous vehicles combine LiDAR, radar, and cameras for 3D bounding box estimation with depth information.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What is image super-resolution and which architecture commonly achieves it?', '["Upscaling a low-resolution image to higher resolution; often done with CNNs or diffusion models (e.g., ESRGAN)","Compressing images","Segmenting images","Detecting edges only"]'::jsonb, 'Upscaling a low-resolution image to higher resolution; often done with CNNs or diffusion models (e.g., ESRGAN)', 'Super-resolution models learn to hallucinate plausible high-frequency detail from low-resolution inputs.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What is the role of the discriminator in a GAN used for image synthesis?', '["Classifying images as real or generated, providing a training signal to improve the generator","Generating images","Segmenting images","Computing reconstruction loss"]'::jsonb, 'Classifying images as real or generated, providing a training signal to improve the generator', 'The discriminator is an adversarial critic; its feedback drives the generator to produce increasingly realistic images.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is domain adaptation in computer vision?', '["Adapting a model trained in one visual domain (e.g., synthetic) to perform well in another (e.g., real world)","Training on more images","A type of pooling","Image translation only"]'::jsonb, 'Adapting a model trained in one visual domain (e.g., synthetic) to perform well in another (e.g., real world)', 'Domain adaptation addresses covariate shift between source and target domains, often using adversarial or alignment methods.', true);
END;
$$;

-- ============================================================
-- TOPIC 8: Data Ethics & Privacy
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Data Ethics & Privacy' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'Is it okay to share someone else''s personal information without asking them?', '["No, you should always ask first","Yes, if it is interesting","Only if they are famous","Only online"]'::jsonb, 'No, you should always ask first', 'Respecting privacy means asking permission before sharing information about other people.', true),
  (gen_random_uuid(), tid, 'story', 37, 'What is personal information?', '["Details that identify you, like your name, address, or photo","Any number","A password only","A public fact"]'::jsonb, 'Details that identify you, like your name, address, or photo', 'Personal information includes any data that can identify a specific individual.', true),
  (gen_random_uuid(), tid, 'story', 38, 'Why should you keep your passwords secret?', '["So no one else can pretend to be you and access your accounts","Passwords are just for fun","To make them easier to remember","Everyone else already knows them"]'::jsonb, 'So no one else can pretend to be you and access your accounts', 'Passwords protect your accounts; sharing them could allow others to access your private information.', true),
  (gen_random_uuid(), tid, 'story', 39, 'An AI system learns only from pictures of people with one skin color. What problem might this cause?', '["It might not work well for people with other skin colors","It will be faster","It will be more accurate","No problems at all"]'::jsonb, 'It might not work well for people with other skin colors', 'Training data that lacks diversity creates biased AI systems that perform poorly for underrepresented groups.', true),
  (gen_random_uuid(), tid, 'story', 40, 'What does it mean for an AI to be "fair"?', '["It works equally well for all people and does not treat groups differently","It runs very fast","It uses a lot of data","It is very expensive"]'::jsonb, 'It works equally well for all people and does not treat groups differently', 'A fair AI system does not produce biased outcomes that disadvantage any group of people.', true),
  (gen_random_uuid(), tid, 'story', 41, 'If a website collects your birthday and name, what should it tell you?', '["Why it is collecting that information and how it will be used","Nothing","Only your name","Just the date"]'::jsonb, 'Why it is collecting that information and how it will be used', 'Transparency in data collection means users should know why their data is being gathered and how it will be used.', true),
  (gen_random_uuid(), tid, 'story', 42, 'What is consent in data privacy?', '["Giving permission before your information is collected or used","A type of password","A kind of data","An AI rule"]'::jsonb, 'Giving permission before your information is collected or used', 'Consent means a person agrees, with understanding, to allow their data to be collected or used.', true),
  (gen_random_uuid(), tid, 'story', 43, 'Should an AI making important decisions about people (like loans) be able to explain why it decided?', '["Yes, people deserve to understand decisions that affect them","No, AI never needs to explain","Only for big companies","Only for robots"]'::jsonb, 'Yes, people deserve to understand decisions that affect them', 'Explainability ensures people can understand and challenge AI decisions that impact their lives.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What should you do if an app asks for permission to access all your photos but only needs one?', '["Only give it permission for what it actually needs","Give it everything","Delete all your photos","Ignore the request"]'::jsonb, 'Only give it permission for what it actually needs', 'The principle of data minimization says apps should only access the minimum data necessary for their function.', true),
  (gen_random_uuid(), tid, 'story', 45, 'What is bias in AI?', '["When an AI treats some people unfairly because it learned from unbalanced data","When AI is very slow","When AI makes mathematical errors","When AI forgets data"]'::jsonb, 'When an AI treats some people unfairly because it learned from unbalanced data', 'AI bias occurs when models learn unfair patterns from training data and apply them to real decisions.', true),
  (gen_random_uuid(), tid, 'story', 46, 'If a company gets hacked and your information is stolen, what is that called?', '["A data breach","A data backup","A data gift","A data update"]'::jsonb, 'A data breach', 'A data breach is when private information is accessed or stolen by unauthorized parties.', true),
  (gen_random_uuid(), tid, 'story', 47, 'What does "anonymous data" mean?', '["Data with identifying details removed so it cannot be linked to a specific person","Data about famous people","Secret government data","Personal data with a password"]'::jsonb, 'Data with identifying details removed so it cannot be linked to a specific person', 'Anonymization removes or masks personal identifiers, protecting privacy while allowing data to be used.', true),
  (gen_random_uuid(), tid, 'story', 48, 'Who is responsible for making sure an AI treats people fairly?', '["The people and companies who build and use it","Only the computer","Only the government","Nobody"]'::jsonb, 'The people and companies who build and use it', 'Developers, companies, and policymakers all share responsibility for ensuring AI systems are fair and ethical.', true),
  (gen_random_uuid(), tid, 'story', 49, 'If an AI in a game always makes the hardest level for kids and easy for adults, is that fair?', '["No, difficulty should not be based on age automatically without consent","Yes, adults always win","Only if kids ask","Yes, it is just a game"]'::jsonb, 'No, difficulty should not be based on age automatically without consent', 'Automatically treating people differently based on a characteristic without their knowledge is a fairness concern.', true),
  (gen_random_uuid(), tid, 'story', 50, 'What is the right to be forgotten?', '["The right to ask companies to delete your personal data","The right to forget passwords","A law about AI robots","A type of backup"]'::jsonb, 'The right to ask companies to delete your personal data', 'The right to erasure (GDPR) allows individuals to request deletion of their personal data from a company''s systems.', true),
  (gen_random_uuid(), tid, 'story', 51, 'What does transparency mean when talking about AI?', '["Being open about how an AI system works and makes decisions","Making the code look pretty","Running AI faster","Using colorful charts"]'::jsonb, 'Being open about how an AI system works and makes decisions', 'Transparency means AI systems and their developers are open about how decisions are made and what data is used.', true),
  (gen_random_uuid(), tid, 'story', 52, 'If someone builds an AI that harms people by accident, are they still responsible?', '["Yes, builders have a responsibility to test for harms before releasing AI","No, accidents don''t count","Only if they knew","Only for big harms"]'::jsonb, 'Yes, builders have a responsibility to test for harms before releasing AI', 'Responsible AI development requires thorough testing and risk assessment before deployment, even for unintended harms.', true),
  (gen_random_uuid(), tid, 'story', 53, 'Why is diverse training data important for AI fairness?', '["It helps the AI learn to work for all types of people, not just a few","It makes AI faster","It reduces storage needed","It makes AI cheaper"]'::jsonb, 'It helps the AI learn to work for all types of people, not just a few', 'Diverse training data ensures AI models learn patterns that generalize across different demographics and contexts.', true),
  (gen_random_uuid(), tid, 'story', 54, 'What is a privacy policy?', '["A document that explains what data a website collects and how it is used","A type of password","A list of employees","A security camera"]'::jsonb, 'A document that explains what data a website collects and how it is used', 'Privacy policies inform users about data collection practices and their rights regarding that data.', true),
  (gen_random_uuid(), tid, 'story', 55, 'Should children''s data be protected with extra care?', '["Yes, children need stronger protections because they may not fully understand privacy","No, everyone has equal protection","Only in schools","Only for medical data"]'::jsonb, 'Yes, children need stronger protections because they may not fully understand privacy', 'Laws like COPPA provide enhanced protections for children''s data, recognizing their special vulnerability.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What does GDPR stand for and what is its main purpose?', '["General Data Protection Regulation — a European law protecting individuals'' data rights","Google Data Privacy Rules","General Device Protection Regulation","Global Data Policy Regulation"]'::jsonb, 'General Data Protection Regulation — a European law protecting individuals'' data rights', 'GDPR establishes data rights (access, erasure, portability) and requires lawful, transparent data processing.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What is algorithmic bias?', '["Systematic and unfair discrimination in AI outputs due to biased data or design","Random errors in algorithms","Any model with imperfect accuracy","A fast algorithm"]'::jsonb, 'Systematic and unfair discrimination in AI outputs due to biased data or design', 'Algorithmic bias produces outcomes that unfairly advantage or disadvantage groups, often reflecting historical inequalities.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What is the principle of data minimization?', '["Collecting only the data that is necessary for the specified purpose","Collecting as much data as possible","Minimizing data storage costs","Using small datasets for training"]'::jsonb, 'Collecting only the data that is necessary for the specified purpose', 'Data minimization limits collection to what is strictly needed, reducing privacy risk and data breach impact.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What does differential privacy protect against?', '["Inferring information about specific individuals from published statistics or model outputs","General data breaches","Password theft","Network attacks"]'::jsonb, 'Inferring information about specific individuals from published statistics or model outputs', 'Differential privacy adds calibrated noise to data or outputs so individual records cannot be identified.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is a fairness metric in AI?', '["A quantitative measure of whether an AI treats groups equitably (e.g., equal accuracy across demographics)","Model speed","Training data size","Parameter count"]'::jsonb, 'A quantitative measure of whether an AI treats groups equitably (e.g., equal accuracy across demographics)', 'Fairness metrics like demographic parity or equalized odds measure disparate impact across protected groups.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What is model explainability (XAI)?', '["Techniques that help humans understand why an AI made a specific prediction","Making models faster","Reducing model size","A type of training"]'::jsonb, 'Techniques that help humans understand why an AI made a specific prediction', 'XAI methods like LIME and SHAP provide human-interpretable explanations for AI predictions.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What is the "right to explanation" in AI ethics?', '["The right of individuals to receive a meaningful explanation for automated decisions affecting them","The right to see all model code","The right to delete data only","The right to vote on AI"]'::jsonb, 'The right of individuals to receive a meaningful explanation for automated decisions affecting them', 'GDPR''s Article 22 grants rights related to automated decision-making, including access to explanations.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What is data anonymization and why is it imperfect?', '["Removing identifiers from data; imperfect because re-identification is sometimes possible using auxiliary data","Perfect privacy protection","Encrypting data","Deleting data"]'::jsonb, 'Removing identifiers from data; imperfect because re-identification is sometimes possible using auxiliary data', 'Research shows many "anonymized" datasets can be re-identified by combining them with other public information.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is surveillance capitalism?', '["Business model that monetizes personal data collected through digital surveillance for targeted advertising","A government surveillance program","Paying people for their data","Selling surveillance cameras"]'::jsonb, 'Business model that monetizes personal data collected through digital surveillance for targeted advertising', 'Surveillance capitalism, coined by Shoshana Zuboff, describes how tech platforms commodify behavioral data.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is the accountability principle in data ethics?', '["Organizations must be responsible for how they collect, use, and protect personal data","Data should be shared freely","Only governments handle data ethics","Accountability applies only to security breaches"]'::jsonb, 'Organizations must be responsible for how they collect, use, and protect personal data', 'Accountability means data controllers are legally and ethically responsible for their data processing practices.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What is a deepfake and what ethical concerns does it raise?', '["AI-generated synthetic media that realistically replaces faces/voices; concerns include misinformation and non-consensual content","A type of data breach","A privacy policy","A machine learning benchmark"]'::jsonb, 'AI-generated synthetic media that realistically replaces faces/voices; concerns include misinformation and non-consensual content', 'Deepfakes can spread disinformation, damage reputations, and create non-consensual intimate imagery.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is informed consent in data collection?', '["Users agree after being clearly informed about what data is collected, why, and how it will be used","Clicking any button","Signing up for a service","Reading terms of service only"]'::jsonb, 'Users agree after being clearly informed about what data is collected, why, and how it will be used', 'Informed consent requires comprehensible disclosure and voluntary agreement before data collection begins.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is the difference between individual and group privacy harms?', '["Individual harm affects one person (identity theft); group harm affects whole communities (discriminatory profiling)","They are the same","Group harm is always more serious","Individual harm does not exist in data ethics"]'::jsonb, 'Individual harm affects one person (identity theft); group harm affects whole communities (discriminatory profiling)', 'AI systems can harm specific people and also entire demographic groups through discriminatory patterns.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What is the purpose of a Data Protection Officer (DPO)?', '["To oversee an organization''s data protection strategy and ensure GDPR compliance","To manage IT systems","To build AI models","To handle customer service"]'::jsonb, 'To oversee an organization''s data protection strategy and ensure GDPR compliance', 'GDPR requires certain organizations to appoint a DPO responsible for monitoring data protection practices.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What are the ethical concerns with facial recognition technology?', '["Mass surveillance, racial bias (higher error rates for darker skin), and privacy violations","It is too slow","It requires too much storage","It only works outdoors"]'::jsonb, 'Mass surveillance, racial bias (higher error rates for darker skin), and privacy violations', 'Facial recognition raises serious concerns about accuracy disparities, consent, and enabling authoritarian surveillance.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is the open data movement and what tension does it create with privacy?', '["Making government and research data publicly available for transparency vs. risking exposure of personal information","Sharing code freely","Publishing all AI models","A data backup strategy"]'::jsonb, 'Making government and research data publicly available for transparency vs. risking exposure of personal information', 'Open data increases transparency and research utility but must be balanced against individuals'' privacy rights.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is fairness through unawareness and why is it insufficient?', '["Removing protected attributes (race, gender) from the model; insufficient because proxies can still encode them","A complete fairness solution","The only fairness metric needed","A legal requirement"]'::jsonb, 'Removing protected attributes (race, gender) from the model; insufficient because proxies can still encode them', 'Proxies like zip code or name can correlate with protected attributes, reintroducing bias even after removal.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What does the concept of "purpose limitation" mean in data privacy?', '["Data collected for one purpose cannot be repurposed without new consent","Data must be deleted immediately","Data can be used for any purpose","Limits apply only to medical data"]'::jsonb, 'Data collected for one purpose cannot be repurposed without new consent', 'Purpose limitation prevents feature creep in data use, requiring fresh consent for any new data use cases.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is a bias audit in AI systems?', '["A systematic evaluation of an AI system''s outputs for disparate impact across demographic groups","A security audit","A performance benchmark","A training data review only"]'::jsonb, 'A systematic evaluation of an AI system''s outputs for disparate impact across demographic groups', 'Bias audits test model predictions across groups to identify and quantify unfair disparities before deployment.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What ethical principle asks AI developers to anticipate and prevent harms before they occur?', '["Proactive/preventive ethics (non-maleficence)","Reactive ethics only","Market-driven ethics","Accuracy maximization"]'::jsonb, 'Proactive/preventive ethics (non-maleficence)', 'Non-maleficence requires actively working to avoid causing harm, not just responding after harm occurs.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the epsilon (ε) parameter in differential privacy and what does a smaller ε mean?', '["ε bounds privacy loss — smaller ε means stronger privacy guarantees but more noise added to outputs","ε is the learning rate","ε measures accuracy","ε controls data size"]'::jsonb, 'ε bounds privacy loss — smaller ε means stronger privacy guarantees but more noise added to outputs', 'ε-differential privacy guarantees that any single record''s inclusion changes output probability by at most e^ε.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'What is the impossibility result connecting three fairness criteria?', '["Calibration, equal false positive rates, and equal false negative rates cannot all hold simultaneously when base rates differ across groups","All three can always be satisfied","Only two can be achieved with enough data","It applies only to classification"]'::jsonb, 'Calibration, equal false positive rates, and equal false negative rates cannot all hold simultaneously when base rates differ across groups', 'Chouldechova (2017) proved these three criteria are mathematically incompatible when prevalence differs across groups.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is federated learning and how does it preserve privacy?', '["Training models on distributed devices without centralizing raw data; only model updates are shared","Distributing training data to multiple servers","Encrypting centralized data","A type of differential privacy"]'::jsonb, 'Training models on distributed devices without centralizing raw data; only model updates are shared', 'Federated learning keeps user data on-device; only gradient updates are aggregated, reducing centralized data exposure.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'What is model inversion attack in the context of AI privacy?', '["Reconstructing training data from a model''s outputs or parameters","Inverting model weights","Reversing gradient descent","A type of adversarial example"]'::jsonb, 'Reconstructing training data from a model''s outputs or parameters', 'Model inversion attacks exploit model responses to reverse-engineer sensitive training data attributes.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is membership inference attack?', '["Determining whether a specific record was used to train a model by analyzing its output behavior","Attacking model weights","A denial-of-service attack","A type of data poisoning"]'::jsonb, 'Determining whether a specific record was used to train a model by analyzing its output behavior', 'Membership inference exploits overfitting: models output higher confidence on training examples, revealing membership.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What is the distinction between individual fairness and group fairness?', '["Individual fairness: similar individuals treated similarly; group fairness: protected groups have equal statistical outcomes","They are identical","Group fairness is always more important","Individual fairness applies only to regression"]'::jsonb, 'Individual fairness: similar individuals treated similarly; group fairness: protected groups have equal statistical outcomes', 'Individual fairness is metric-based and person-level; group fairness aggregates outcomes across demographic groups.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is the concept of algorithmic accountability?', '["Requiring that developers, deployers, and regulators can audit, explain, and take responsibility for AI system outcomes","AI making its own decisions","Code being open source","A type of model evaluation"]'::jsonb, 'Requiring that developers, deployers, and regulators can audit, explain, and take responsibility for AI system outcomes', 'Accountability frameworks create chains of responsibility and audit mechanisms for consequential AI systems.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What is the EU AI Act''s risk-based classification approach?', '["Categorizing AI systems into unacceptable, high, limited, and minimal risk with proportionate regulation","A single rule for all AI","Only regulating robotics","A voluntary code of conduct"]'::jsonb, 'Categorizing AI systems into unacceptable, high, limited, and minimal risk with proportionate regulation', 'The EU AI Act bans unacceptable-risk systems and imposes strict requirements on high-risk applications like biometric ID.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is data poisoning in machine learning security?', '["Injecting malicious training examples to corrupt model behavior","A privacy attack on inference","Overwriting model weights","Stealing training data"]'::jsonb, 'Injecting malicious training examples to corrupt model behavior', 'Data poisoning attacks manipulate the training set to introduce backdoors or degrade performance on specific inputs.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is the concept of contextual integrity in privacy theory?', '["Information flows appropriately when they match the norms of the context in which data was originally shared","Data should never flow between contexts","Privacy only applies to medical data","Information flows are always appropriate"]'::jsonb, 'Information flows appropriately when they match the norms of the context in which data was originally shared', 'Helen Nissenbaum''s contextual integrity argues privacy is violated when data flows break contextual norms, not merely when data is shared.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is the tension between model utility and differential privacy?', '["Adding noise for privacy reduces accuracy; the privacy-utility tradeoff requires choosing acceptable ε","More noise always improves accuracy","Differential privacy has no cost","Utility is unrelated to privacy"]'::jsonb, 'Adding noise for privacy reduces accuracy; the privacy-utility tradeoff requires choosing acceptable ε', 'DP noise degrades model performance; practitioners must balance privacy budget (ε) against acceptable accuracy loss.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is counterfactual fairness?', '["A prediction is counterfactually fair if it would be the same had the individual belonged to a different protected group","A type of demographic parity","Equal false positive rates","A causal inference method only"]'::jsonb, 'A prediction is counterfactually fair if it would be the same had the individual belonged to a different protected group', 'Counterfactual fairness uses causal graphs to ensure decisions do not change based on protected attribute in the causal model.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is disparate impact versus disparate treatment in algorithmic decision-making?', '["Disparate impact: neutral practice has discriminatory effect; disparate treatment: explicitly uses protected attributes","They are legally identical","Disparate treatment is always legal","Disparate impact requires intent"]'::jsonb, 'Disparate impact: neutral practice has discriminatory effect; disparate treatment: explicitly uses protected attributes', 'Disparate treatment is intentional discrimination; disparate impact is unintentional but still legally and ethically problematic.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is the role of a model card in AI transparency?', '["Documenting a model''s intended use, performance across demographic groups, and known limitations","A business card for the AI company","A model architecture diagram","A training cost summary"]'::jsonb, 'Documenting a model''s intended use, performance across demographic groups, and known limitations', 'Model cards (Mitchell et al., 2019) provide standardized documentation to enable informed deployment decisions.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is the principle of data stewardship in AI ethics?', '["Treating data as a resource held in trust for users, with obligations to protect and use it responsibly","Owning data outright","Maximizing data collection","Deleting all data after use"]'::jsonb, 'Treating data as a resource held in trust for users, with obligations to protect and use it responsibly', 'Data stewardship recognizes that those who hold data have fiduciary-like responsibilities to those whose data it is.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What is secure multi-party computation (SMPC) and how does it relate to AI privacy?', '["Multiple parties jointly compute a function over their private inputs without revealing those inputs to each other","Encrypting data at rest","A type of federated learning","Differential privacy for groups"]'::jsonb, 'Multiple parties jointly compute a function over their private inputs without revealing those inputs to each other', 'SMPC enables privacy-preserving collaborative AI training where no party sees others'' raw data.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is the COMPAS recidivism algorithm controversy and what fairness violation was alleged?', '["It was found to have equal false positive rates for Black defendants but unequal with other metrics; sparked fairness debate","It was 100% accurate","It used illegal data","It was too slow for courts"]'::jsonb, 'It was found to have equal false positive rates for Black defendants but unequal with other metrics; sparked fairness debate', 'ProPublica''s COMPAS analysis revealed that satisfying one fairness criterion (calibration) violated others across racial groups.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What is a dataset datasheet and why is it important for responsible AI?', '["Documentation describing dataset composition, collection process, uses, and limitations to enable informed use","A spreadsheet of training data","A model performance summary","A privacy policy for datasets"]'::jsonb, 'Documentation describing dataset composition, collection process, uses, and limitations to enable informed use', 'Datasheets for Datasets (Gebru et al., 2018) promote transparency about training data to identify potential biases and misuse.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What is value alignment in AI safety and ethics?', '["Ensuring AI systems pursue goals consistent with human values and intentions","Training AI on values datasets","A type of reinforcement learning","A legal compliance framework"]'::jsonb, 'Ensuring AI systems pursue goals consistent with human values and intentions', 'The alignment problem asks how to specify and instill human values into AI systems that might otherwise pursue unintended objectives.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is the dual-use dilemma in AI research?', '["The same AI capability can be used for beneficial or harmful purposes, creating ethical challenges for researchers","AI models that serve two users","Publishing code openly","Using two different datasets"]'::jsonb, 'The same AI capability can be used for beneficial or harmful purposes, creating ethical challenges for researchers', 'Dual-use AI (e.g., generative models, surveillance tools) requires researchers to weigh societal benefits against misuse risks.', true);
END;
$$;

-- ============================================================
-- TOPIC 9: Robotics & Automation
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Robotics & Automation' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'What is a robot?', '["A machine that can be programmed to do tasks automatically","A toy car","A cartoon character","A computer game"]'::jsonb, 'A machine that can be programmed to do tasks automatically', 'A robot is a programmable machine that can carry out physical tasks, often in the real world.', true),
  (gen_random_uuid(), tid, 'story', 37, 'What allows a robot to sense the world around it?', '["Sensors","Wheels","Batteries","Antennas only"]'::jsonb, 'Sensors', 'Sensors are devices that detect information from the environment, like cameras, microphones, or distance detectors.', true),
  (gen_random_uuid(), tid, 'story', 38, 'What part of a robot lets it move, like motors or arms?', '["Actuators","Sensors","Processors","Batteries"]'::jsonb, 'Actuators', 'Actuators are the mechanical components (motors, servos, pistons) that allow robots to move and interact.', true),
  (gen_random_uuid(), tid, 'story', 39, 'What does a robot do with the information from its sensors?', '["Uses it to decide what action to take next","Deletes it","Stores it forever","Sends it to the internet"]'::jsonb, 'Uses it to decide what action to take next', 'Robots process sensor data through a controller or computer to make decisions and act accordingly.', true),
  (gen_random_uuid(), tid, 'story', 40, 'Which household device is an example of simple automation?', '["A dishwasher that automatically runs a washing cycle","A book","A pencil","A window"]'::jsonb, 'A dishwasher that automatically runs a washing cycle', 'Automated appliances like dishwashers perform repeated tasks without human intervention once started.', true),
  (gen_random_uuid(), tid, 'story', 41, 'What does autonomous mean for a robot?', '["It can do things on its own without a human controlling every move","It only moves backward","It needs a remote control always","It is very small"]'::jsonb, 'It can do things on its own without a human controlling every move', 'An autonomous robot makes its own decisions based on sensor data and programming without constant human input.', true),
  (gen_random_uuid(), tid, 'story', 42, 'Robot arms in car factories help build cars. This is an example of what?', '["Industrial automation","Magic tricks","Customer service","Teaching"]'::jsonb, 'Industrial automation', 'Industrial robots perform repetitive manufacturing tasks like welding and assembly with precision and speed.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What does a drone (flying robot) use to stay in the air?', '["Spinning propellers and a controller to balance","Flapping wings","Balloons","Magnets"]'::jsonb, 'Spinning propellers and a controller to balance', 'Drones use multiple propellers and onboard control systems to generate lift and maintain stable flight.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What is a self-driving car an example of?', '["An autonomous robot vehicle","A video game car","A toy","A regular car with GPS"]'::jsonb, 'An autonomous robot vehicle', 'Self-driving cars use sensors, AI, and control systems to navigate roads without human drivers.', true),
  (gen_random_uuid(), tid, 'story', 45, 'A robot that helps surgeons perform operations uses which technology?', '["Robotic surgery / medical robotics","Video games","Industrial conveyor belts","Household appliances"]'::jsonb, 'Robotic surgery / medical robotics', 'Medical robots like the da Vinci system assist surgeons with precision movements in minimally invasive procedures.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What is the most basic loop a robot follows? It senses, then it thinks, then it what?', '["Acts","Sleeps","Stops","Recharges"]'::jsonb, 'Acts', 'The sense-think-act cycle is the fundamental loop: sense the environment, process data, take an action.', true),
  (gen_random_uuid(), tid, 'story', 47, 'Why do robots used in dangerous places, like volcanoes or bomb disposal, help humans?', '["They can work in environments too dangerous for people","They are faster at talking","They cost nothing","They never make mistakes"]'::jsonb, 'They can work in environments too dangerous for people', 'Robots can operate in hazardous environments, reducing risk to human life in dangerous situations.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What is a robotic vacuum cleaner an example of?', '["Domestic automation (home robot)","Industrial robot","Medical robot","Space robot"]'::jsonb, 'Domestic automation (home robot)', 'Robotic vacuums are consumer robots that autonomously clean floors using sensors and mapping.', true),
  (gen_random_uuid(), tid, 'story', 49, 'What does GPS help a robot do?', '["Know where it is in the world","See in the dark","Pick up objects","Count items"]'::jsonb, 'Know where it is in the world', 'GPS provides location coordinates, enabling robots and autonomous vehicles to navigate precisely.', true),
  (gen_random_uuid(), tid, 'story', 50, 'A robot on Mars collects rock samples. What type of robot is it?', '["Space exploration robot","Factory robot","Medical robot","Home robot"]'::jsonb, 'Space exploration robot', 'Space robots like Mars rovers explore environments inaccessible to humans and conduct scientific research.', true),
  (gen_random_uuid(), tid, 'story', 51, 'What is a key safety concern when robots work near humans?', '["Making sure robots do not accidentally hurt people","Making robots faster","Making robots smaller","Giving robots names"]'::jsonb, 'Making sure robots do not accidentally hurt people', 'Human-robot safety is critical — robots must sense and respond to humans to avoid collisions or injuries.', true),
  (gen_random_uuid(), tid, 'story', 52, 'Automation means having machines do tasks that humans used to do. What is one benefit?', '["Tasks can be done faster, more consistently, and without tiring","Machines are always smarter than humans","Automation requires no maintenance","Robots are free to use"]'::jsonb, 'Tasks can be done faster, more consistently, and without tiring', 'Automation increases speed, consistency, and endurance, reducing errors caused by human fatigue.', true),
  (gen_random_uuid(), tid, 'story', 53, 'What does a robot need to avoid bumping into things as it moves?', '["Sensors to detect obstacles","Wheels only","A very bright light","Loud sounds"]'::jsonb, 'Sensors to detect obstacles', 'Obstacle detection sensors (ultrasonic, lidar, cameras) allow robots to perceive and avoid objects in their path.', true),
  (gen_random_uuid(), tid, 'story', 54, 'What is programming a robot?', '["Giving it a set of instructions that tell it what to do in different situations","Painting it a new color","Charging its battery","Naming it"]'::jsonb, 'Giving it a set of instructions that tell it what to do in different situations', 'Programming provides the logic and decision-making rules that govern a robot''s behavior.', true),
  (gen_random_uuid(), tid, 'story', 55, 'Robots that look and act like humans are called what?', '["Humanoid robots","Animal robots","Flying robots","Mini robots"]'::jsonb, 'Humanoid robots', 'Humanoid robots are designed with human-like bodies and movements, intended to interact naturally with people.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What does PID stand for in robot control systems?', '["Proportional-Integral-Derivative — a feedback control algorithm","Position-Inertia-Degrees","Parallel Input Driver","Programmed Instruction Database"]'::jsonb, 'Proportional-Integral-Derivative — a feedback control algorithm', 'PID controllers calculate an error value and apply corrections based on proportional, integral, and derivative terms.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What is SLAM in robotics?', '["Simultaneous Localization and Mapping — building a map while tracking position","Sensor Localization and Manipulation","Sequential Logic and Motion","Software Locomotion and Automation"]'::jsonb, 'Simultaneous Localization and Mapping — building a map while tracking position', 'SLAM enables a robot to explore an unknown environment, building a map and localizing itself within it simultaneously.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What is the degrees of freedom (DOF) of a robotic arm?', '["The number of independent movements (joints) the arm can make","The arm''s weight","The number of sensors","The arm''s length"]'::jsonb, 'The number of independent movements (joints) the arm can make', 'DOF indicates how many independent axes of motion a robot has; more DOF means more flexible movement.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What is forward kinematics in robotics?', '["Calculating end-effector position from joint angles","Calculating joint angles from end position","Path planning","Obstacle avoidance"]'::jsonb, 'Calculating end-effector position from joint angles', 'Forward kinematics uses joint angles to compute where the robot''s end (gripper) will be in space.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is inverse kinematics?', '["Calculating joint angles needed to reach a desired end-effector position","Computing velocity","Forward motion planning","Sensor calibration"]'::jsonb, 'Calculating joint angles needed to reach a desired end-effector position', 'Inverse kinematics solves the reverse problem: given a target position, find the joint configuration to achieve it.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What type of sensor measures distance using reflected sound waves?', '["Ultrasonic sensor","LiDAR","Camera","GPS"]'::jsonb, 'Ultrasonic sensor', 'Ultrasonic sensors emit sound pulses and measure the return time to calculate distance to nearby objects.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What does LiDAR stand for and what does it measure?', '["Light Detection and Ranging — measures distances using laser pulses","Light Imaging Detector and Ranging","Linear Detection Array","Laser Integrated Direction and Route"]'::jsonb, 'Light Detection and Ranging — measures distances using laser pulses', 'LiDAR emits laser beams and measures return times to create precise 3D point clouds of the environment.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What is an end-effector on a robot arm?', '["The tool at the end of the arm (gripper, welder, etc.) that interacts with the environment","The arm''s base joint","The control computer","The power supply"]'::jsonb, 'The tool at the end of the arm (gripper, welder, etc.) that interacts with the environment', 'End-effectors are interchangeable tools that define what manipulation task the robotic arm can perform.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is ROS (Robot Operating System)?', '["An open-source middleware framework for building robot software with standard tools and libraries","A physical robot OS","A simulation only tool","A type of sensor"]'::jsonb, 'An open-source middleware framework for building robot software with standard tools and libraries', 'ROS provides hardware abstraction, device drivers, communication, and tools widely used in robotics research.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is the role of an IMU (Inertial Measurement Unit) in robotics?', '["Measuring acceleration and angular velocity to track orientation and movement","Measuring distance to walls","Providing GPS location","Detecting color"]'::jsonb, 'Measuring acceleration and angular velocity to track orientation and movement', 'IMUs combine accelerometers and gyroscopes to estimate a robot''s motion, tilt, and orientation.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What is collision detection in robot motion planning?', '["Checking whether a planned path would cause the robot to hit obstacles before executing it","Detecting when the robot crashes","A type of sensor","Real-time path execution"]'::jsonb, 'Checking whether a planned path would cause the robot to hit obstacles before executing it', 'Collision detection algorithms verify that planned trajectories are obstacle-free before the robot moves.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is the difference between a teleoperated robot and an autonomous robot?', '["Teleoperated is controlled by a human in real time; autonomous makes its own decisions","They are the same","Autonomous robots are always smaller","Teleoperated robots are faster"]'::jsonb, 'Teleoperated is controlled by a human in real time; autonomous makes its own decisions', 'Teleoperation requires continuous human input; autonomy allows the robot to execute tasks without moment-to-moment control.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is a swarm of robots?', '["Many simple robots that coordinate through local interactions to achieve complex collective behavior","A single large robot","A robot with many arms","Remote-controlled robots"]'::jsonb, 'Many simple robots that coordinate through local interactions to achieve complex collective behavior', 'Swarm robotics uses decentralized coordination inspired by social insects to achieve scalable, robust collective tasks.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What is the actuator-sensor loop that drives robot behavior called?', '["The sense-plan-act (or perception-action) cycle","The input-output cycle","The read-write cycle","The fetch-execute cycle"]'::jsonb, 'The sense-plan-act (or perception-action) cycle', 'Robots continuously sense their environment, plan a response, and act, repeating this cycle in real time.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is a collaborative robot (cobot)?', '["A robot designed to work safely alongside humans, sharing workspace","An industrial robot behind safety fences","A robot controlled by another robot","A remote-operated vehicle"]'::jsonb, 'A robot designed to work safely alongside humans, sharing workspace', 'Cobots use force sensing and speed limits to interact safely with humans in shared workspaces.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is localization in robotics?', '["Determining the robot''s position and orientation within a known map","Building a new map","Path planning","Sensor calibration"]'::jsonb, 'Determining the robot''s position and orientation within a known map', 'Localization uses sensor data and a map to estimate where the robot currently is in its environment.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is the purpose of a Kalman filter in robotics?', '["Estimating system state (e.g., position) by combining noisy sensor measurements with a motion model","Filtering camera images","Removing sensor noise only","Planning paths"]'::jsonb, 'Estimating system state (e.g., position) by combining noisy sensor measurements with a motion model', 'Kalman filters optimally fuse measurements and predictions to maintain a best estimate of robot state over time.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'What is path planning in robotics?', '["Finding a collision-free trajectory from a start position to a goal position","Controlling joint angles","Mapping the environment","Detecting objects"]'::jsonb, 'Finding a collision-free trajectory from a start position to a goal position', 'Path planning algorithms (A*, RRT, Dijkstra) compute obstacle-free routes through the robot''s configuration space.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What safety standard governs collaborative robot speeds near humans?', '["ISO/TS 15066 — defines speed, force, and power limits for cobots","ISO 9001","IEC 61508","IEEE 802.11"]'::jsonb, 'ISO/TS 15066 — defines speed, force, and power limits for cobots', 'ISO/TS 15066 specifies biomechanical limits and operational modes for safe human-robot collaboration.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What is reinforcement learning used for in robotics?', '["Teaching robots to perform tasks through trial and error with reward signals","Labeling training data","Building hardware","Calibrating sensors"]'::jsonb, 'Teaching robots to perform tasks through trial and error with reward signals', 'RL-trained robots learn to walk, grasp, or navigate by maximizing cumulative reward through simulated or physical interaction.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the configuration space (C-space) in robot motion planning?', '["The space of all possible robot configurations (joint angles); obstacles in C-space represent configurations causing collisions","Physical workspace only","The set of reachable end-effector positions","The sensor''s field of view"]'::jsonb, 'The space of all possible robot configurations (joint angles); obstacles in C-space represent configurations causing collisions', 'Planning in C-space transforms complex 3D collision avoidance into path planning in a higher-dimensional abstract space.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'What is the RRT (Rapidly-exploring Random Tree) algorithm used for?', '["Sampling-based motion planning in high-dimensional spaces by growing a tree of random configurations","A control algorithm","A SLAM technique","A sensor fusion method"]'::jsonb, 'Sampling-based motion planning in high-dimensional spaces by growing a tree of random configurations', 'RRT randomly samples C-space and expands a tree toward samples, efficiently exploring high-DOF configuration spaces.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is model predictive control (MPC) and why is it used in robotics?', '["Optimizing a control sequence over a receding horizon using a system model, enabling constraint-aware real-time control","A feedforward-only controller","A type of PID","An RL policy"]'::jsonb, 'Optimizing a control sequence over a receding horizon using a system model, enabling constraint-aware real-time control', 'MPC solves an optimization problem at each timestep using a predictive model to compute near-optimal control actions.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'How does an Extended Kalman Filter (EKF) differ from a standard Kalman Filter?', '["EKF linearizes nonlinear system dynamics using Jacobians; standard KF assumes linear dynamics","They are identical","EKF uses particle sampling","Standard KF handles nonlinear systems"]'::jsonb, 'EKF linearizes nonlinear system dynamics using Jacobians; standard KF assumes linear dynamics', 'EKF applies first-order Taylor approximation to handle nonlinear motion and observation models common in robotics.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is a particle filter (Monte Carlo localization) and why is it suited to robot localization?', '["Represents belief as a set of weighted samples, handling non-Gaussian distributions common in localization","A deterministic filter","A type of EKF","A path planning algorithm"]'::jsonb, 'Represents belief as a set of weighted samples, handling non-Gaussian distributions common in localization', 'Particle filters approximate arbitrary probability distributions, allowing robots to represent multimodal uncertainty about position.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What is impedance control in robot manipulation?', '["Regulating the dynamic relationship (stiffness, damping) between force and motion at the end-effector","Position control only","Force sensing calibration","Joint angle control"]'::jsonb, 'Regulating the dynamic relationship (stiffness, damping) between force and motion at the end-effector', 'Impedance control enables compliant interaction with the environment by controlling the robot''s apparent mechanical impedance.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is sim-to-real transfer in robot learning?', '["Training robot policies in simulation then deploying on real hardware, addressing the reality gap","Training only on real data","Using identical simulators to real robots","A type of sensor calibration"]'::jsonb, 'Training robot policies in simulation then deploying on real hardware, addressing the reality gap', 'Sim-to-real techniques like domain randomization help bridge the gap between simulated and real physics.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What is whole-body control (WBC) for humanoid robots?', '["Simultaneously controlling all joints to satisfy multiple prioritized tasks (balance, manipulation, locomotion)","Only controlling the arms","Controlling a single joint","A type of end-effector"]'::jsonb, 'Simultaneously controlling all joints to satisfy multiple prioritized tasks (balance, manipulation, locomotion)', 'WBC optimizes joint torques to achieve hierarchically prioritized objectives across the full-body kinematic chain.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is the Jacobian matrix in robot kinematics?', '["Maps joint velocities to end-effector velocities; its transpose relates end-effector forces to joint torques","Computes forward kinematics","A rotation matrix","The robot''s inertia matrix"]'::jsonb, 'Maps joint velocities to end-effector velocities; its transpose relates end-effector forces to joint torques', 'The Jacobian is central to velocity kinematics and force control, linking joint space to task space.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is loop closure in SLAM?', '["Detecting when the robot revisits a previously mapped location and correcting accumulated drift in the map","Starting a new map","A type of path planning","Sensor re-calibration"]'::jsonb, 'Detecting when the robot revisits a previously mapped location and correcting accumulated drift in the map', 'Loop closure recognition allows SLAM to correct map inconsistencies that accumulate from small pose estimation errors.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is tactile sensing in robotics and why is it important for manipulation?', '["Sensing contact forces and textures via artificial skin or pressure sensors; enables delicate grasping","Vision-based sensing","Proximity sensing","Audio sensing"]'::jsonb, 'Sensing contact forces and textures via artificial skin or pressure sensors; enables delicate grasping', 'Tactile sensing provides contact feedback for object recognition, grasp stability, and safe interaction with fragile objects.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is the Denavit-Hartenberg (DH) convention?', '["A systematic parameterization of robot link and joint geometry for kinematic analysis","A control algorithm","A path planning method","A sensor type"]'::jsonb, 'A systematic parameterization of robot link and joint geometry for kinematic analysis', 'DH convention uses four parameters (a, d, α, θ) per joint to define the transformation between consecutive frames.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is the role of a grasp planner in robotic manipulation?', '["Determining stable gripper configurations for reliably grasping objects with specific shapes","Path planning for the arm","Force control only","End-effector selection"]'::jsonb, 'Determining stable gripper configurations for reliably grasping objects with specific shapes', 'Grasp planning considers object geometry, friction, and reachability to find configurations that resist external forces.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is torque-based control versus position-based control in robot joints?', '["Torque control directly applies force/torque for compliant interaction; position control moves to a target angle rigidly","They are identical","Torque control is always less precise","Position control is only for mobile robots"]'::jsonb, 'Torque control directly applies force/torque for compliant interaction; position control moves to a target angle rigidly', 'Torque control enables force-sensitive manipulation; position control achieves precise joint angles for rigid tasks.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is the occupancy grid map used in mobile robotics?', '["A discretized representation of the environment where each cell stores the probability of being occupied","A list of obstacles only","A 3D point cloud","A topological map"]'::jsonb, 'A discretized representation of the environment where each cell stores the probability of being occupied', 'Occupancy grids represent environment geometry probabilistically, useful for navigation and collision avoidance.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What is the difference between reactive and deliberative robot architectures?', '["Reactive responds immediately to sensor data (no model); deliberative builds a model and plans before acting","They are identical","Reactive is always slower","Deliberative never uses sensors"]'::jsonb, 'Reactive responds immediately to sensor data (no model); deliberative builds a model and plans before acting', 'Hybrid architectures combine reactive behaviors for fast response with deliberative planning for complex goal achievement.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is digital twin technology in industrial robotics?', '["A virtual real-time simulation of a physical robot or system used for monitoring, testing, and optimization","A backup robot","A remote control system","A type of sensor"]'::jsonb, 'A virtual real-time simulation of a physical robot or system used for monitoring, testing, and optimization', 'Digital twins mirror physical systems in software, enabling predictive maintenance and virtual commissioning.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What is the challenge of simultaneous manipulation and locomotion in legged robots?', '["Maintaining balance while moving limbs for manipulation requires coordinated whole-body dynamics and real-time re-planning","Only relevant for wheeled robots","Separate controllers always suffice","It is only a software problem"]'::jsonb, 'Maintaining balance while moving limbs for manipulation requires coordinated whole-body dynamics and real-time re-planning', 'Legged manipulators must manage dynamic balance, contact forces, and manipulation simultaneously at high control rates.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What is behavior cloning and how is it used in robot learning?', '["Supervised learning on expert demonstrations to teach a robot a policy","A type of RL","Reward shaping","A SLAM technique"]'::jsonb, 'Supervised learning on expert demonstrations to teach a robot a policy', 'Behavior cloning maps states to actions by imitating recorded expert demonstrations, but suffers from distribution shift.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is the concept of safety constraints in robot control and give an example?', '["Hard limits on forces, speeds, or positions that must never be violated; e.g., maximum torque to prevent injury","Soft limits that can be exceeded","Only applicable to surgical robots","A type of sensor"]'::jsonb, 'Hard limits on forces, speeds, or positions that must never be violated; e.g., maximum torque to prevent injury', 'Safety constraints are formally verified limits enforced by the control system to guarantee safe operation around humans.', true);
END;
$$;

-- ============================================================
-- TOPIC 10: Generative AI
-- ============================================================
DO $$
DECLARE tid UUID;
BEGIN
  SELECT id INTO tid FROM public.topics WHERE title = 'Generative AI' LIMIT 1;

  INSERT INTO public.questions (id, topic_id, track, order_index, prompt, options, correct_answer, explanation, is_free) VALUES
  (gen_random_uuid(), tid, 'story', 36, 'What is generative AI?', '["AI that can create new things like stories, pictures, and music","AI that only sorts data","AI that counts numbers","AI that cleans your room"]'::jsonb, 'AI that can create new things like stories, pictures, and music', 'Generative AI creates new content — text, images, audio — rather than just analyzing existing data.', true),
  (gen_random_uuid(), tid, 'story', 37, 'When an AI writes a short story for you based on your idea, what is it doing?', '["Generating text","Sorting words","Deleting stories","Counting sentences"]'::jsonb, 'Generating text', 'Text generation creates new written content based on a prompt using a language model.', true),
  (gen_random_uuid(), tid, 'story', 38, 'Which AI tool can turn your text description into a picture?', '["An image generation AI (like DALL-E or Midjourney)","A calculator","A search engine","A spell checker"]'::jsonb, 'An image generation AI (like DALL-E or Midjourney)', 'Text-to-image models generate pictures from text descriptions using generative AI.', true),
  (gen_random_uuid(), tid, 'story', 39, 'What do we call the words or instructions you give to a generative AI to get a result?', '["A prompt","A command line","A delete request","A search result"]'::jsonb, 'A prompt', 'A prompt is the input text or instruction you give to a generative AI model to guide its output.', true),
  (gen_random_uuid(), tid, 'story', 40, 'Can generative AI sometimes make up information that sounds true but is not?', '["Yes, this is called hallucination","No, AI is always 100% correct","Only for pictures","Only for music"]'::jsonb, 'Yes, this is called hallucination', 'Generative AI can produce convincing but false information, known as hallucination.', true),
  (gen_random_uuid(), tid, 'story', 41, 'What is a chatbot powered by generative AI able to do?', '["Have a conversation and answer questions in natural language","Only say yes or no","Only tell jokes","Only search the web"]'::jsonb, 'Have a conversation and answer questions in natural language', 'Generative AI chatbots can understand and respond to a wide range of conversational messages.', true),
  (gen_random_uuid(), tid, 'story', 42, 'If an AI creates a fake photo of someone that never happened, what concern does that raise?', '["It could spread false information (misinformation)","It makes photos look better","It is always helpful","It speeds up photography"]'::jsonb, 'It could spread false information (misinformation)', 'AI-generated fake images can be used to deceive people, raising serious misinformation concerns.', true),
  (gen_random_uuid(), tid, 'story', 43, 'What is an AI music generator able to create?', '["New songs and melodies from text descriptions or style prompts","Only silence","Only drum beats","Only classical music"]'::jsonb, 'New songs and melodies from text descriptions or style prompts', 'AI music generators produce original audio compositions based on style, mood, or text prompts.', true),
  (gen_random_uuid(), tid, 'story', 44, 'What does it mean to "fine-tune" a generative AI for a specific job?', '["Train it further on specific examples so it gets better at that particular task","Delete its memory","Make it work offline","Change its name"]'::jsonb, 'Train it further on specific examples so it gets better at that particular task', 'Fine-tuning adapts a pre-trained generative model to perform well on a specific domain or task.', true),
  (gen_random_uuid(), tid, 'story', 45, 'What should you always do when using AI-generated content for school?', '["Check if it is accurate and give credit to the AI tool used","Copy it without checking","Never tell your teacher","Pretend you wrote it yourself"]'::jsonb, 'Check if it is accurate and give credit to the AI tool used', 'Academic integrity requires verifying AI-generated information and being transparent about how it was produced.', true),
  (gen_random_uuid(), tid, 'story', 46, 'What is a deepfake video?', '["A video where someone''s face is replaced by AI with another person''s face","A very deep ocean video","A video made with lots of effects","A long movie"]'::jsonb, 'A video where someone''s face is replaced by AI with another person''s face', 'Deepfakes use generative AI to swap faces in videos, raising concerns about fraud and misinformation.', true),
  (gen_random_uuid(), tid, 'story', 47, 'Generative AI learned to create by looking at what?', '["Huge amounts of existing content (text, images, etc.)","A single example","Only the work of one artist","Nothing — it invents from scratch"]'::jsonb, 'Huge amounts of existing content (text, images, etc.)', 'Generative models are trained on massive datasets of human-created content and learn to produce similar outputs.', true),
  (gen_random_uuid(), tid, 'story', 48, 'What is one positive way generative AI can help students?', '["Explaining difficult concepts in simple terms","Doing all homework without learning","Replacing teachers entirely","Making school disappear"]'::jsonb, 'Explaining difficult concepts in simple terms', 'Generative AI can act as a tutor, rephrasing and explaining topics at appropriate levels to aid understanding.', true),
  (gen_random_uuid(), tid, 'story', 49, 'If two people give the same prompt to a generative AI, will they always get the exact same answer?', '["Not always — generative AI has randomness built in","Yes, always identical","Only if they type slowly","Only on weekends"]'::jsonb, 'Not always — generative AI has randomness built in', 'Generative models use probabilistic sampling, producing varied outputs even for identical prompts.', true),
  (gen_random_uuid(), tid, 'story', 50, 'What is the most important thing to remember about AI-generated facts?', '["Always verify them with trusted sources","They are always correct","They are always wrong","They come from books only"]'::jsonb, 'Always verify them with trusted sources', 'AI-generated facts can be inaccurate or hallucinated; critical verification with reliable sources is essential.', true),
  (gen_random_uuid(), tid, 'story', 51, 'What kind of AI generates realistic human-like voices from text?', '["Text-to-speech (voice synthesis) AI","A keyboard","A microphone only","A translator"]'::jsonb, 'Text-to-speech (voice synthesis) AI', 'Voice synthesis AI generates natural-sounding human speech from written text input.', true),
  (gen_random_uuid(), tid, 'story', 52, 'Why do AI companies need a lot of computing power to train generative AI?', '["Because they process enormous amounts of data with billions of calculations","Computers are slow today","Storage is cheap","Training takes only one second"]'::jsonb, 'Because they process enormous amounts of data with billions of calculations', 'Training large generative models requires massive parallel computation on thousands of specialized chips.', true),
  (gen_random_uuid(), tid, 'story', 53, 'Can generative AI create computer code?', '["Yes, it can write and explain code in many programming languages","No, only humans write code","Only very simple code ever","Only in one language"]'::jsonb, 'Yes, it can write and explain code in many programming languages', 'Code-generation models (like GitHub Copilot) can write, complete, and explain programs in many languages.', true),
  (gen_random_uuid(), tid, 'story', 54, 'What is a good habit when reading something written by AI?', '["Think critically and check the facts independently","Believe everything immediately","Share it without reading","Ignore it completely"]'::jsonb, 'Think critically and check the facts independently', 'Critical thinking and independent fact-checking are essential when consuming AI-generated content.', true),
  (gen_random_uuid(), tid, 'story', 55, 'What makes generative AI different from a search engine?', '["Generative AI creates new answers; search engines find existing web pages","They are the same thing","Search engines generate images","Generative AI only searches books"]'::jsonb, 'Generative AI creates new answers; search engines find existing web pages', 'Generative AI synthesizes novel responses; search engines retrieve and rank existing documents.', true),

  (gen_random_uuid(), tid, 'levels', 36, 'What architecture underpins most modern large language models (LLMs)?', '["The Transformer architecture","Recurrent Neural Network","Convolutional Neural Network","Decision tree"]'::jsonb, 'The Transformer architecture', 'Transformers with self-attention enable parallel training on large corpora, powering GPT, BERT, and similar LLMs.', true),
  (gen_random_uuid(), tid, 'levels', 37, 'What is a foundation model?', '["A large model pre-trained on broad data that can be adapted to many downstream tasks","A model for civil engineering","A small task-specific model","A model that only classifies images"]'::jsonb, 'A large model pre-trained on broad data that can be adapted to many downstream tasks', 'Foundation models (GPT-4, DALL-E 3, etc.) are general-purpose models that form the base for specific applications.', true),
  (gen_random_uuid(), tid, 'levels', 38, 'What does RLHF stand for and how does it improve LLMs?', '["Reinforcement Learning from Human Feedback — aligns model outputs with human preferences","Recurrent Loop Hidden Function","Random Learning Human Filter","Relative Loss Heuristic Feedback"]'::jsonb, 'Reinforcement Learning from Human Feedback — aligns model outputs with human preferences', 'RLHF trains a reward model from human comparisons, then fine-tunes the LLM using RL to maximize the reward.', true),
  (gen_random_uuid(), tid, 'levels', 39, 'What is the context window in an LLM?', '["The maximum number of tokens the model can process at one time","The model''s memory from past sessions","The number of training examples","The screen size"]'::jsonb, 'The maximum number of tokens the model can process at one time', 'The context window limits how much text (prompt + response) the model considers at once during inference.', true),
  (gen_random_uuid(), tid, 'levels', 40, 'What is few-shot prompting?', '["Providing a small number of input-output examples in the prompt to guide the model","Training a new model","Using fewer parameters","Reducing context window"]'::jsonb, 'Providing a small number of input-output examples in the prompt to guide the model', 'Few-shot prompting shows the model example input-output pairs, helping it understand the desired format or task.', true),
  (gen_random_uuid(), tid, 'levels', 41, 'What is a GAN (Generative Adversarial Network)?', '["Two competing networks — generator creates fake data; discriminator distinguishes real from fake","A single classification network","A type of recurrent network","An attention mechanism"]'::jsonb, 'Two competing networks — generator creates fake data; discriminator distinguishes real from fake', 'GAN training is a minimax game: the generator improves by fooling the discriminator, which improves at detection.', true),
  (gen_random_uuid(), tid, 'levels', 42, 'What is a diffusion model?', '["A generative model that learns to denoise data, starting from noise and iteratively producing clean outputs","A type of GAN","An encoder-only model","A recurrent network for images"]'::jsonb, 'A generative model that learns to denoise data, starting from noise and iteratively producing clean outputs', 'Diffusion models (Stable Diffusion, DALL-E 3) reverse a noising process, producing high-quality images from noise.', true),
  (gen_random_uuid(), tid, 'levels', 43, 'What ethical concern relates to generative AI training on artists'' work without permission?', '["Copyright and consent — artists'' styles and specific works may be reproduced without compensation","AI is too accurate","Training takes too long","The images are low quality"]'::jsonb, 'Copyright and consent — artists'' styles and specific works may be reproduced without compensation', 'Using copyrighted creative work in training without consent or compensation raises legal and ethical questions.', true),
  (gen_random_uuid(), tid, 'levels', 44, 'What is temperature in text generation?', '["A parameter controlling randomness — high temperature produces more creative/diverse outputs","The model''s physical temperature","A training hyperparameter","The number of output tokens"]'::jsonb, 'A parameter controlling randomness — high temperature produces more creative/diverse outputs', 'Higher temperature flattens the probability distribution, increasing diversity; lower temperature makes outputs more focused.', true),
  (gen_random_uuid(), tid, 'levels', 45, 'What is the difference between zero-shot and few-shot generation?', '["Zero-shot uses only the prompt with no examples; few-shot provides examples in the prompt","Zero-shot uses more data","Few-shot requires retraining","They produce identical outputs"]'::jsonb, 'Zero-shot uses only the prompt with no examples; few-shot provides examples in the prompt', 'Zero-shot relies purely on the model''s pre-trained knowledge; few-shot uses in-context examples to guide generation.', true),
  (gen_random_uuid(), tid, 'levels', 46, 'What is the multimodal capability of models like GPT-4V or Gemini?', '["Processing and generating multiple types of data (text, images, audio) in a single model","Using multiple GPUs","Having multiple context windows","Generating only images"]'::jsonb, 'Processing and generating multiple types of data (text, images, audio) in a single model', 'Multimodal models handle diverse input/output types, enabling tasks like image captioning and visual question answering.', true),
  (gen_random_uuid(), tid, 'levels', 47, 'What is model grounding in generative AI?', '["Connecting model outputs to factual, verifiable information from a knowledge base or real-time sources","Making the model smaller","Grounding the model physically","A type of fine-tuning"]'::jsonb, 'Connecting model outputs to factual, verifiable information from a knowledge base or real-time sources', 'Grounding reduces hallucinations by ensuring generated content is anchored to verified facts or retrieved documents.', true),
  (gen_random_uuid(), tid, 'levels', 48, 'What is AI watermarking?', '["Embedding invisible signals in AI-generated content to identify its origin","A security measure for passwords","Encrypting model weights","A type of fine-tuning"]'::jsonb, 'Embedding invisible signals in AI-generated content to identify its origin', 'Watermarking helps detect AI-generated text or images, supporting content provenance and combating misinformation.', true),
  (gen_random_uuid(), tid, 'levels', 49, 'What is the emergent capability phenomenon in LLMs?', '["Abilities that appear suddenly at certain model scales that were absent in smaller models","A planned feature","A type of overfitting","A fine-tuning result only"]'::jsonb, 'Abilities that appear suddenly at certain model scales that were absent in smaller models', 'Emergent capabilities (e.g., in-context learning, arithmetic) appear unexpectedly as model scale crosses certain thresholds.', true),
  (gen_random_uuid(), tid, 'levels', 50, 'What is a system prompt in LLM applications?', '["An instruction given to the model before the user prompt to set behavior, tone, or constraints","A user message","The model''s first response","A fine-tuning input"]'::jsonb, 'An instruction given to the model before the user prompt to set behavior, tone, or constraints', 'System prompts configure the model''s persona and operational guidelines without being visible in the conversation.', true),
  (gen_random_uuid(), tid, 'levels', 51, 'What is the role of tokenization in LLMs?', '["Converting text into numerical token IDs that the model processes — words or subwords are mapped to vocabulary indices","Training the model","Selecting output tokens","Compressing model weights"]'::jsonb, 'Converting text into numerical token IDs that the model processes — words or subwords are mapped to vocabulary indices', 'Tokenization is the first step in LLM processing, converting raw text into discrete numerical inputs.', true),
  (gen_random_uuid(), tid, 'levels', 52, 'What is top-p (nucleus) sampling in text generation?', '["Sampling from the smallest set of tokens whose cumulative probability exceeds p, balancing quality and diversity","Sampling the top p tokens by count","Using only the top-1 token","A training method"]'::jsonb, 'Sampling from the smallest set of tokens whose cumulative probability exceeds p, balancing quality and diversity', 'Nucleus sampling dynamically adjusts the candidate token set, avoiding low-probability tokens while preserving creativity.', true),
  (gen_random_uuid(), tid, 'levels', 53, 'Why is output safety filtering important in deployed generative AI?', '["To prevent models from generating harmful, offensive, or dangerous content","To speed up inference","To reduce model size","To improve accuracy metrics"]'::jsonb, 'To prevent models from generating harmful, offensive, or dangerous content', 'Safety filters detect and block policy-violating content to protect users and prevent misuse.', true),
  (gen_random_uuid(), tid, 'levels', 54, 'What is in-context learning?', '["A model''s ability to perform new tasks from examples given in the prompt without weight updates","Training the model online","A type of fine-tuning","Caching previous responses"]'::jsonb, 'A model''s ability to perform new tasks from examples given in the prompt without weight updates', 'In-context learning emerged in large LLMs — they adapt behavior based on prompt examples without gradient updates.', true),
  (gen_random_uuid(), tid, 'levels', 55, 'What is the environmental cost concern associated with training large generative AI models?', '["Massive energy consumption for compute and cooling, contributing to carbon emissions","Models use too much RAM","Training data is expensive","Inference is cheap"]'::jsonb, 'Massive energy consumption for compute and cooling, contributing to carbon emissions', 'Training frontier models can consume megawatt-hours of electricity; the carbon footprint is a growing sustainability concern.', true),

  (gen_random_uuid(), tid, 'sandbox', 36, 'What is the score function estimator (REINFORCE) used for in training generative models?', '["Estimating gradients through non-differentiable sampling operations using log-probability gradients","A type of attention","A supervised learning loss","A tokenization method"]'::jsonb, 'Estimating gradients through non-differentiable sampling operations using log-probability gradients', 'REINFORCE/score function estimator enables gradient-based optimization when the model contains discrete sampling steps.', true),
  (gen_random_uuid(), tid, 'sandbox', 37, 'What is the reparameterization trick in VAEs and why is it necessary?', '["Expressing the stochastic sample as a deterministic function of parameters and separate noise, enabling gradient flow","A data augmentation technique","A way to reduce model size","A type of normalization"]'::jsonb, 'Expressing the stochastic sample as a deterministic function of parameters and separate noise, enabling gradient flow', 'Reparameterizing z = μ + σ·ε (ε~N(0,1)) makes sampling differentiable, allowing backpropagation through the latent space.', true),
  (gen_random_uuid(), tid, 'sandbox', 38, 'What is mode collapse in GAN training?', '["The generator learns to produce only a few types of outputs, ignoring the data distribution''s diversity","The discriminator collapses to constant output","Training loss becomes zero","The model becomes too large"]'::jsonb, 'The generator learns to produce only a few types of outputs, ignoring the data distribution''s diversity', 'Mode collapse occurs when the generator finds and exploits a limited set of outputs that fool the discriminator.', true),
  (gen_random_uuid(), tid, 'sandbox', 39, 'How does classifier-free guidance improve image quality in diffusion models?', '["Training both conditional and unconditional models; at inference, extrapolating in the direction of the conditional score for better adherence to prompts","A type of GAN training","Adding more denoising steps","Increasing model size only"]'::jsonb, 'Training both conditional and unconditional models; at inference, extrapolating in the direction of the conditional score for better adherence to prompts', 'CFG scales the conditional score beyond the unconditional baseline, trading diversity for fidelity to the text prompt.', true),
  (gen_random_uuid(), tid, 'sandbox', 40, 'What is the ELBO (Evidence Lower BOund) and what is it used for in generative modeling?', '["A tractable lower bound on log-likelihood used to train VAEs and other latent variable models","The upper bound on accuracy","The learning rate bound","A regularization term"]'::jsonb, 'A tractable lower bound on log-likelihood used to train VAEs and other latent variable models', 'ELBO = E[log p(x|z)] - KL(q(z|x)||p(z)), decomposing into reconstruction and regularization terms for VAE training.', true),
  (gen_random_uuid(), tid, 'sandbox', 41, 'What is latent diffusion (used in Stable Diffusion) and why is it more efficient?', '["Performing the diffusion process in the compressed latent space of a VAE rather than pixel space","Using fewer denoising steps","A type of GAN","Training only on small images"]'::jsonb, 'Performing the diffusion process in the compressed latent space of a VAE rather than pixel space', 'Latent diffusion reduces compute by compressing images to a lower-dimensional latent space before applying diffusion.', true),
  (gen_random_uuid(), tid, 'sandbox', 42, 'What is scaling law in large language models?', '["Empirical relationship showing that model performance improves predictably with compute, parameters, and data","A maximum model size rule","A training time limit","A memory constraint"]'::jsonb, 'Empirical relationship showing that model performance improves predictably with compute, parameters, and data', 'Kaplan et al.''s scaling laws show loss decreases as a power law with model size, data, and compute budget.', true),
  (gen_random_uuid(), tid, 'sandbox', 43, 'What is the Chinchilla scaling law and how did it change model training?', '["Models should be trained on ~20 tokens per parameter for compute-optimal training; prior models were undertrained","Bigger models always outperform smaller ones","Data does not matter beyond 1B tokens","Compute is the only factor"]'::jsonb, 'Models should be trained on ~20 tokens per parameter for compute-optimal training; prior models were undertrained', 'Hoffmann et al. (2022) showed GPT-3-scale models needed far more training data for compute-optimal performance.', true),
  (gen_random_uuid(), tid, 'sandbox', 44, 'What is speculative decoding in LLM inference?', '["Using a small draft model to propose tokens, then verifying with the large model in parallel, reducing latency","Generating multiple responses simultaneously","A type of beam search","Caching attention keys"]'::jsonb, 'Using a small draft model to propose tokens, then verifying with the large model in parallel, reducing latency', 'Speculative decoding achieves 2-3x speedup by having a large model verify batches of draft tokens in one forward pass.', true),
  (gen_random_uuid(), tid, 'sandbox', 45, 'What is LoRA (Low-Rank Adaptation) and how does it enable efficient fine-tuning?', '["Adding low-rank decomposition matrices to frozen pre-trained weights, training only those small additions","Full model fine-tuning","Pruning neurons during fine-tuning","A type of quantization"]'::jsonb, 'Adding low-rank decomposition matrices to frozen pre-trained weights, training only those small additions', 'LoRA decomposes weight updates as W = W₀ + BA where B,A are low-rank, drastically reducing trainable parameters.', true),
  (gen_random_uuid(), tid, 'sandbox', 46, 'What is the difference between autoregressive and non-autoregressive generation?', '["AR generates one token at a time conditioned on previous tokens; NAR generates all tokens in parallel (faster but less accurate)","They are identical","NAR always produces better quality","AR generates in reverse"]'::jsonb, 'AR generates one token at a time conditioned on previous tokens; NAR generates all tokens in parallel (faster but less accurate)', 'NAR models sacrifice some quality for dramatic speed gains by removing sequential dependencies in generation.', true),
  (gen_random_uuid(), tid, 'sandbox', 47, 'What is the Wasserstein distance (used in WGANs) and why is it better than JS divergence for GANs?', '["It provides meaningful gradients even when distributions do not overlap, stabilizing GAN training","It is always smaller","It requires fewer training steps","It measures color distance"]'::jsonb, 'It provides meaningful gradients even when distributions do not overlap, stabilizing GAN training', 'JS divergence saturates when distributions are disjoint; Wasserstein distance remains smooth, giving useful gradient signal.', true),
  (gen_random_uuid(), tid, 'sandbox', 48, 'What is constitutional AI (CAI) and how does it reduce dependence on human feedback?', '["Using a written set of principles for the model to self-critique and revise responses, reducing the volume of human labels needed","Only using human feedback","A hardware constraint","A type of fine-tuning"]'::jsonb, 'Using a written set of principles for the model to self-critique and revise responses, reducing the volume of human labels needed', 'CAI (Anthropic) uses AI-generated critique and revision guided by principles, scaling alignment with less human annotation.', true),
  (gen_random_uuid(), tid, 'sandbox', 49, 'What is beam search in text generation and what is its limitation?', '["Keeping top-k partial sequences at each step for better quality; tends to produce generic, repetitive outputs","Random sampling","A type of temperature scaling","Top-p sampling"]'::jsonb, 'Keeping top-k partial sequences at each step for better quality; tends to produce generic, repetitive outputs', 'Beam search finds high-probability sequences but sacrifices diversity, often producing dull or repetitive text.', true),
  (gen_random_uuid(), tid, 'sandbox', 50, 'What is a retrieval-augmented generation (RAG) architecture and what problem does it address?', '["Combining a retriever (fetching relevant documents) with a generator (conditioning on them) to reduce hallucinations and add factual grounding","A type of fine-tuning","A GAN variant","A tokenization method"]'::jsonb, 'Combining a retriever (fetching relevant documents) with a generator (conditioning on them) to reduce hallucinations and add factual grounding', 'RAG reduces hallucination by grounding generation in retrieved passages, enabling knowledge to be updated without retraining.', true),
  (gen_random_uuid(), tid, 'sandbox', 51, 'What are the FID (Frechet Inception Distance) and CLIP score used to evaluate?', '["FID measures visual quality and diversity of generated images; CLIP score measures text-image alignment","Only model speed","Training loss","Memory usage"]'::jsonb, 'FID measures visual quality and diversity of generated images; CLIP score measures text-image alignment', 'FID compares Inception feature distributions between real and generated images; CLIP score measures prompt adherence.', true),
  (gen_random_uuid(), tid, 'sandbox', 52, 'What is tool use (function calling) in LLM systems?', '["Enabling LLMs to invoke external APIs, calculators, or search engines to extend capabilities beyond pure generation","A type of fine-tuning","An attention mechanism","A tokenization strategy"]'::jsonb, 'Enabling LLMs to invoke external APIs, calculators, or search engines to extend capabilities beyond pure generation', 'Function calling allows LLMs to delegate tasks (computation, retrieval, actions) to specialized external tools.', true),
  (gen_random_uuid(), tid, 'sandbox', 53, 'What is the concept of a "jailbreak" in the context of LLM safety?', '["A prompt engineering technique that bypasses a model''s safety guidelines to produce restricted content","A debugging method","A way to speed up inference","A data preprocessing step"]'::jsonb, 'A prompt engineering technique that bypasses a model''s safety guidelines to produce restricted content', 'Jailbreaks exploit model behavior to circumvent safety training, motivating ongoing adversarial robustness research.', true),
  (gen_random_uuid(), tid, 'sandbox', 54, 'What distinguishes a reasoning model (like o1/o3) from a standard autoregressive LLM?', '["Reasoning models generate internal chain-of-thought steps (thinking tokens) before responding, improving accuracy on complex tasks","They use more parameters always","They only generate code","They cannot use tools"]'::jsonb, 'Reasoning models generate internal chain-of-thought steps (thinking tokens) before responding, improving accuracy on complex tasks', 'Models trained with extended thinking allocate compute to deliberate reasoning, dramatically improving math and logic performance.', true),
  (gen_random_uuid(), tid, 'sandbox', 55, 'What is the principal-agent alignment problem as it applies to agentic AI systems?', '["Ensuring an autonomous AI agent pursues the goals of its principals (users, developers) rather than misaligned sub-goals","A multi-agent communication protocol","A fine-tuning strategy","A hardware issue"]'::jsonb, 'Ensuring an autonomous AI agent pursues the goals of its principals (users, developers) rather than misaligned sub-goals', 'As LLM agents act over long horizons with tool use, ensuring they remain aligned with human intent becomes critical.', true);
END;
$$;
